export const PAGES: LandingPage[] = [{ "slug": "airsaas-et-les-experts-de-la-transfo", "type": "solution", "meta": { "title": "AirSaas et les experts de la transformation", "description": "AirSaas, la solution la plus simple pour partager en continu une vue macro d'un projet transverse, d'un programme ou d'un portefeuille projet. Surdélivrez vos missions avec AirSaas." }, "sections": [{ "type": "hero", "tag": "SOLUTIONS", "title": "Surdélivrer vos missions avec", "titleSuffix": " AirSaas", "body": "<p>AirSaas c'est la solution la plus simple pour partager en continu une vue macro d'un projet transverse, d'un programme ou d'un portefeuille projet et mettre l'impact chez vos client au coeur de votre stratégie.<br/><br/>Êtes-vous prêt à construire la bonne gouvernance&nbsp;pour vos missions ? Vous pouvez <em>aligner vos donneurs d'ordres</em> et vos parties prenantes sans effort et vous concentrer sur l'essentiel : <em>dépasser les attentes de vos clients</em> sur le delivery.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/668566e02bd789b8eb53e8fd_Register%20illustration.webp", "imageAlt": "AirSaas celebration" }, { "type": "intro", "title": "Engagez-vous pour la transformation", "body": "<p>Expert transfo, ESN, Cabinets de conseils, Manager de transition, Consultants, PMO, Directeur de programmes ou de projets, qu'attendent <strong>vos clients</strong> ? Des PowerPoints pour leur expliquer la vie ou un impact immédiat sur le périmètre qui <strong>vous est confié</strong> ?<br/>Outiller sa mission c'est démontrer par la preuve qu'une bonne gouvernance, qu'un bon pilotage se structure et peut faire grandir la culture projet de votre client.<br/>AirSaas est une entreprise étendue qui partage avec des experts une <strong>volonté commune</strong> d'accompagner ceux qui font, ceux qui décident et ceux qui organisent <strong>à mieux travailler ensemble</strong>.</p>" }, { "type": "testimonials", "testimonials": [{ "name": "Joanne Deval", "role": "Technology, Business and People. Advising, Mentoring and Teaching. #CIO#data #cyber #IT #IA #board member", "text": "Merci Thomas POITAU ! Une belle aventure humaine qui commence, suite en effet à une histoire de hasard et de confiance, et aussi de convictions et de valeurs partagées 😊", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/672b7ea76145ce12e1a414fc_Joanne%20Deval.jpeg", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7186242034779746304/?commentUrn=urn%3Ali%3Acomment%3A%28activity%3A7186242034779746304%2C7186258890311749632%29&dashCommentUrn=urn%3Ali%3Afsd_comment%3A%287186258890311749632%2Curn%3Ali%3Aactivity%3A7186242034779746304%29" }, { "name": "Roland Bouchut", "role": "Chief Information Officer | Chief Executive Officer | ExCom Member", "text": "Merci Bertran Ruiz Thomas POITAU, travailler avec une équipe aussi engagée est un vrai plaisir 🙂 , et contribuer avec des solutions claires et impactantes pour nos clients communs fait toute la différence !!!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/67a5cd9d94ea875970d1c35e_Roland%20Bouchut.jpg", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7288461778865250304/?commentUrn=urn%3Ali%3Acomment%3A(activity%3A7288461778865250304%2C7288477601730330624)&dashCommentUrn=urn%3Ali%3Afsd_comment%3A(7288477601730330624%2Curn%3Ali%3Aactivity%3A7288461778865250304)" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer-membre FrenchWomenCIO-Administratrice CRiP-VP@Arce Avenir Femmes-ESSEC Alumni", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou .Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/?utm_source=share&utm_medium=member_desktop" }, { "name": "Michaël Sanchez PMP®", "role": "Directeur Projets & Programmes IT | Expert Logiciels Sur Mesure | Certifié PMP, ITIL V4, PSM, PSPO, Swish.ai | Membre PMI & CJD | Fondateur MS Consulting Bureau de Projets Externalisé PPM & ITSM", "text": "Le PPT a disparu depuis longtemps chez nous pour les rapports CODIR/ PIL/MEX... Mais avec AirSaas c'est encore un niveau de performance supplémentaire. Bien outillés, on délivre sec 🏅🥂", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/672909a238949f7e2f5fb208_Michae%CC%88l%20Sanchez.jpeg", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:ugcPost:7183486810319151105?commentUrn=ur%5B%E2%80%A6%5D74420836958208%2Curn%3Ali%3AugcPost%3A7183486810319151105%29" }, { "name": "Benoît Rosaz", "role": "Transformation Digitale - Manager de transition - CIO / CTO - Directeur de projet - Freelance", "text": "AirSaas ne construit pas seulement un outil, mais y adjoint une philosophie, une approche et une communauté dynamique Les Pro. de la Transfo by Airsaas. Bref une vrai SOLUTION Bravo AirSaas", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/6728f6f1b9e8b28a424f1970_Benoi%CC%82t%20Rosaz.jpeg", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7247130712393269248?commentUrn=u%5B%E2%80%A6%5D3993678139392%2Curn%3Ali%3Aactivity%3A7247130712393269248%29" }, { "name": "Thibault Baheux", "role": "Direction de projet & PMO", "text": "La prise de conscience commence à se faire dans les CODIR. Ce qui leur manque par contre, c'est d'avoir une vision concrète du portefeuille de projets de l'organisation, et c'est là qu'entre en jeu Airsaas.", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154da4d1602634d196ad78_tihibault-baheux.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7115238386918940672/?commentUrn=urn:li:comment:(activity:7115238386918940672,7115280062920220672)&dashCommentUrn=urn:li:fsd_comment:(7115280062920220672,urn:li:activity:7115238386918940672)" }] }, { "type": "feature-split", "title": "Se former entre experts, par des pairs", "body": "<p>Dans un format de bootcamp hybride en 4 semaines, participez à 6 masterclass et obtenez les postures et tactiques pour faire d'AirSaas un catalyseur de transformation.<br/><br/>Les deux dernières masterclass en présentiel à Paris sont suivies par les désormais réputés Bal de Promo.<br/><br/>ESN, cabinets de conseils, des bootcamps sur mesure pour vos équipes sont possibles.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65f8389fb184b54765f33b8d_1.webp", "imageAlt": "BootCamp", "primaryCta": { "label": "🗓️ Infos et réservations", "href": "/fr/bootcamp-airsaas-expert-10-18-juin-2025" } }, { "type": "feature-split", "title": "AirSaas dans le tooling des missions", "body": "<p>Chaque mission pour accompagner des clients à repenser leur Target Operating Model.<br/>Outillés avec AirSaas, vous imprimez une nouvelle donne chez vos clients et vous prouvez qu'en structurant la gouvernance d'un projet, d'un programme et en simplifiant le reporting, vous vous concentrez sur l'essentiel : la qualité du delivery.<br/>Airsaas vous fournit sa solution PPM et vous pouvez l'utiliser pour vos clients grâce mode multi-workspace.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65f84d82c72005c3ac0b0ef7_AirSaas%20Tools.webp", "imageAlt": "AirSaas : people + process + tool", "reversed": true, "primaryCta": { "label": "Je book une démo", "href": "https://meetings.hubspot.com/bertran-ruiz/demo-airsaas-team" } }, { "type": "feature-split", "title": "You never walk alone", "body": "<p>AirSaas est une entreprise étendue et on partage avec sa Communauté des Pro. de la Transfo. un fit culturel, beaucoup de Co-Business et des events toute l'année.<br/><br/>Nous accueillons de nouveaux membres cooptés ou après un premier échange sur nos attentes et engagements respectifs.<br/><br/>Partenaires, cette communauté de 200+ experts vous intéresse ?</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65f85859a1bf7bf2aba81598_1-min-min.webp", "imageAlt": "LPDT", "primaryCta": { "label": "En savoir plus", "href": "/fr/lesprodelatransfo" } }] }, { "slug": "flash-report", "type": "solution", "meta": { "title": "La solution de flash report automatisée préférée des DSI et PMO", "description": "AirSaas automatise vos reportings projets et fluidifie la prise de décision en Copil. Générez votre flash report en un clic, au format PPT ou PDF, personnalisable aux couleurs de votre entreprise." }, "sections": [{ "type": "hero", "title": "La solution de flash report automatisée préférée des DSI et PMO", "body": "<p>Parce que vous avez plus à apporter à la transformation de votre entreprise que des PowerPoints chronophages, AirSaas automatise vos reportings projets et fluidifie la prise de décision en Copil.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "Une solution de reporting projet à votre image : efficace et moderne", "body": "<p>Sur une interface simple à prendre en main et orientée expérience utilisateur, AirSaas automatise vos reportings projets, avec une idée en tête : aider vos décisionnaires à avoir la bonne vision de votre transformation d'entreprise.</p>", "subSections": [{ "title": "Votre rapport flash généré en un clic", "body": "Finies les longues heures passées sur PowerPoint : votre flash report consolide automatiquement toutes les données-clés à présenter à votre Copil, au format PPT ou PDF." }, { "title": "Un document 100% personnalisable", "body": "Votre flash report a beau être automatisé aux couleurs de votre entreprise, vous gardez la main sur son contenu, et y ajoutez tous les éléments qui vous semblent importants pour prendre les bonnes décisions." }, { "title": "Une journée de travail par semaine économisée", "body": "C'est en moyenne ce qu'économisent les PMO et BRM avec le flash report automatisé d'AirSaas. Focalisez-vous sur la vraie valeur que vous apportez : la gouvernance de votre portefeuille projet, et le coaching des métiers." }] }, { "type": "feature-split", "title": "Toutes vos données consolidées en un seul clic", "body": "<p>Vous passez un temps fou à chercher les informations à droite et à gauche, auprès de vos chefs de projets et sur vos outils de gestion de tâche ? Cette époque est révolue !<br/><br/>AirSaas vous permet d'observer toutes les données relatives à votre portfolio de projets, consolidées et mises à jour en temps réel. La data est homogénéisée, et reportée automatiquement dans votre flash report - le tout en un seul clic.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Des rapports qui facilitent la prise de décision", "body": "<p>La structure de votre flash report AirSaas aide vos décisionnaires à visualiser rapidement le contexte de vos projets, ainsi que les décisions à prendre.<br/><br/>Après des slides d'introduction qui rappellent les grandes lignes de vos projets (tableau de bord, planning, timeline…), les membres du Copil visualisent tout ce dont ils ont besoin pour prendre leurs décisions en deux slides : jalons, statuts, risques et météos des projets, métriques d'avancée, gains attendus, ressources humaines et budgets impliqués…</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Une structure fixe, mais personnalisable", "body": "<p>AirSaas crée automatiquement votre flash report au format .ppt ou .pdf, selon une structure ultra-lisible. Le design de votre présentation est personnalisable aux couleurs de votre entreprise.<br/><br/>Si besoin, customisez le contenu de votre reporting, en y ajoutant des métriques-clés supplémentaires, un récapitulatif des décisions à prendre, ou encore des précisions sur le planning de vos projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report", "reversed": false }, { "type": "cta-highlight", "title": "Choisissez de gagner du temps et du contrôle", "body": "<p>Adoptez dès maintenant une solution efficace de flash report projet</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "Plus qu'une solution de reporting flash : une solution de gouvernance projet complète", "body": "<p>En plus du flash report automatisé, les autres fonctionnalités AirSaas vous font changer votre manière de gouverner votre portefeuille projet.</p>" }, { "type": "feature-split", "title": "Une roadmap collaborative de vos projets", "body": "<p>Avec AirSaas, créez des vues filtrées pour visualiser les éléments-clés de vos différents projets à même la plateforme : points d'attention, retards, météos…<br/><br/>De quoi assurer un pilotage macro de vos projets, pour vous focaliser sur ce qui requiert une attention immédiate de vos équipes métiers et décideurs business.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "timeline projet", "reversed": true }, { "type": "feature-split", "title": "Une vision Kanban qui simplifie votre gouvernance", "body": "<p>Centralisez sur votre dashboard toutes les décisions prises et à prendre sur vos projets, sous un format aisément lisible par toutes vos parties prenantes.<br/><br/>Le but ? Fluidifier la prise de décision, en évitant les données parasites qui rallongent vos réunions.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Des fiches de cadrage de projet collaboratives", "body": "<p>Remplissez vos fiches de cadrage de manière collaborative, et développez une culture projet homogène dans toute l'entreprise.<br/><br/>Avec AirSaas, vos chefs de projet montent en puissance, pour faire avancer plus vite la transformation de votre organisation.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Des intégrations natives pour faciliter la remontée d'informations", "body": "<p>Toutes les informations cruciales provenant des outils de gestion de tâches (Jira, Asana…) sont centralisées sur AirSaas, pour éviter la déperdition d'informations.<br/><br/>Les informations d'avancement de vos projets sont diffusées automatiquement sur vos canaux de communication interne (Microsoft Teams), pour que chacun soit toujours au courant.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "Optimisation des ressources disponibles", "reversed": false }, { "type": "cta", "title": "Faites passer votre gouvernance projet à la vitesse supérieure", "body": "<p>Choisissez une solution PPM collaborative et moderne, qui simplifie votre flash report et accélère vos prises de décisions.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "intro", "title": "Les bonnes pratiques de flash report qui mènent vos projets plus loin, plus vite", "body": "<p>Un bon rapport flash, c'est bien. Mais y associer les bonnes pratiques de gouvernance projet, c'est mieux ! Pensez à appliquer ces trois conseils pour en faire un outil-clé de la transformation de votre entreprise.</p>" }, { "type": "feature-split", "title": "Mettez en valeur le ressenti de vos équipes", "body": "<p>Inclure dans votre reporting les métriques d'avancée de vos projets ne suffit pas. Pour impliquer chacun de manière forte dans vos projets, mettez en avant dans vos présentations les points d'attention ou les succès rencontrés, selon ce que vous en dit votre équipe de pilotage, vos responsables de projet, voire vos utilisateurs finaux. Parce qu'ensemble, on avance plus loin.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a7bb239ce496a6f00ac37f_metier-it.svg", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Définissez votre fréquence d'envoi de reporting", "body": "<p>Faites de vos reportings un véritable rendez-vous pour toutes vos parties prenantes, en définissant une fréquence à laquelle vous envoyez vos rapports. La bonne pratique ? Un reporting mensuel bien ficelé, qui met tout le monde au diapason de l'avancée de la transformation de l'entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "Pilotage de projet", "reversed": true }, { "type": "feature-split", "title": "Envoyez vos reportings projets à l'avance", "body": "<p>Envoyez à tous les membres du Copil votre reporting en amont de votre réunion, et utilisez-le comme support de présentation le jour J. Ainsi, tout le monde visualise les mêmes éléments, et les décisions se prennent plus rapidement.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp" }] }] }, { "slug": "flash-report-projet", "type": "solution", "meta": { "title": "L'outil de flash report projet qui vous fait gagner en temps et en efficacité", "description": "Grâce à AirSaas, automatisez vos flash reports projets, et rendez votre prise de décision plus fluide, plus rapide, tout en alignant les parties prenantes de la transformation de votre entreprise." }, "sections": [{ "type": "hero", "tag": "SOLUTION", "title": "L'outil de ", "titleHighlight": "flash report", "titleSuffix": " projet qui vous fait gagner en temps et en efficacité", "body": "<p>Grâce à AirSaas, automatisez vos flash reports projets, et rendez votre prise de décision plus fluide, plus rapide, tout en alignant les parties prenantes de la transformation de votre entreprise.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "L'outil de flash report projet favori des <strong>DSI et PMO</strong>", "body": "<p>Pour faire vos reportings projets, vous allez probablement chercher les informations à droite et à gauche auprès de vos chefs de projet et métiers, par email et par discussions instantanées, ou bien dans les outils de gestion de tâches, de management de projet et de suivi de projet.</p><p>Un process qui génère une véritable perte de temps dans votre planning - et pire : qui mène à une potentielle déperdition d'informations. Difficile, dans ces conditions, de vous focaliser sur l'essentiel de votre rôle, à savoir : la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">gouvernance de votre portfolio de projets</a>.</p><p>C'est à partir de ce constat que nous avons conçu AirSaas, la solution de flash report projet simplissime, orientée expérience utilisateur. Son but : vous faire gagner un temps précieux sur votre flash report projet, et vous aider à obtenir une vue globale de votre <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-portefeuille-de-projet\">portefeuille de projets</a> en temps réel.</p>" }, { "type": "intro", "title": "Consolidez toutes vos données en <strong>un seul clic</strong>", "body": "<p>Dites adieu aux heures passées sur PowerPoint ! Depuis la plateforme AirSaas, toutes vos données sont consolidées, et vous générez automatiquement un flash report projet clair comme de l'eau de source à transmettre à votre <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">Copil</a>.</p>" }, { "type": "feature-split", "title": "Votre flash report <strong>100% automatisé</strong>", "body": "<p>Sur AirSaas, vous pouvez observer toutes les données que vous souhaitez intégrer à vos reportings projets dans des <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-faire-un-bon-point-davancement-projet\">tableaux de bord consolidés</a>.</p><p>Finie la recherche d'information dans votre outil de gestion de tâche ou de gestion de projet ! Toute votre data est ici, homogénéisée, et automatiquement reportée dans votre flash report projet en un simple clic, au format .ppt ou .pdf.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d742defe0bf46502743b11_Flash%20report%20export%20modal.webp", "imageAlt": "Flash report", "reversed": true }, { "type": "feature-split", "title": "Des <strong>intégrations natives</strong> pour éviter le report de données manuel", "body": "<p>Sur la marketplace AirSaas, vous trouverez des intégrations natives à tous vos outils favoris, pour synchroniser les données qui s'y trouvent automatiquement et en temps réel.</p><p>Intégrations à vos outils de project management (Jira, ClickUp, Asana, Monday), de communication interne (Microsoft Teams) et de gestion de service client (Zendesk) : tout ce qu'il faut pour vous faire gagner encore plus de temps.</p><p>Profitez de la marketplace d'intégrations natives d'AirSaas, qui synchronise votre plateforme PPM à vos outils préférés : gestion de tâches (Jira, ClickUp, Asana, Monday), communication interne (Microsoft Teams) et logiciel de service client (Zendesk).</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives", "reversed": false }, { "type": "intro", "title": "<strong>Personnalisez</strong> votre reporting projet", "body": "<p>Customisez les livrables que vous donnez à voir à vos différentes parties prenantes, grâce à des fonctionnalités de personnalisation de votre flash report projet automatisé.</p>" }, { "type": "feature-split", "title": "Une <strong>structure fixe</strong> hyper-lisible", "body": "<p>La structure automatique de votre flash report est faite pour en simplifier la lecture pour les membres de votre Copil. Elle rappelle les grandes lignes de vos projets (timeline, indicateurs-clés, planning…), avant de détailler les éléments-clés à savoir sur vos projets les plus urgents.</p><p>Jalons, statuts, risques et <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-mettre-une-bonne-meteo-projet\">météos des projets</a>, métriques d'avancée, gains attendus, ressources humaines et budgets sollicités… Vous assurez le suivi des projets grâce à cette structure claire et détaillée à la fois.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "Jalons", "reversed": false }, { "type": "feature-split", "title": "Une personnalisation pour coller à vos <strong>objectifs stratégiques</strong>", "body": "<p>Parce que votre reporting doit ressembler à votre organisation, personnalisez-le aux couleurs de votre entreprise, selon votre charte graphique.</p><p>Besoin d'ajouter à votre flash report projet d'autres données ? Intégrez-y des métriques-clés supplémentaires sur l'avancement du projet, des précisions sur les plannings à venir, ou bien un récapitulatif des décisions qui doivent être prises.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report", "reversed": true }, { "type": "intro", "title": "<strong>Fluidifiez</strong> la prise de décision en Copil", "body": "<p>Grâce à AirSaas, faites de votre flash report projet un véritable outil d'aide à la décision, qui aligne toutes vos parties prenantes autour d'un même objectif stratégique : faire avancer la transformation de votre entreprise.</p>" }, { "type": "feature-split", "title": "Votre reporting : l'allié pour vous aider dans <strong>vos décisions</strong>", "body": "<p>Grâce au flash report d'AirSaas, chaque chef de projet, décisionnaire et sponsor est aligné autour d'un livrable qui facilite les décisions. Parce que piloter des projets nécessite une valeur partagée par tous : la collaboration, grâce à une vision claire et unifiée du portfolio.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "la prise de décision", "reversed": false }, { "type": "feature-split", "title": "Un gain de <strong>temps précieux</strong> pour votre gouvernance projet", "body": "<p>AirSaas fait gagner en moyenne une journée par semaine aux PMO et DSI qui s'en emparent. Focalisez-vous sur la vraie valeur que vous apportez : la gouvernance de votre portefeuille projet, et le coaching des métiers, pour que les projets avancent plus vite, plus loin.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7437ca9f8f8d31e9a639b_Programmes%20analytics.webp", "imageAlt": "Programs", "reversed": true }, { "type": "intro", "title": "Plus qu'une solution de reporting flash : un outil PPM projet <strong>moderne et simplissime</strong>", "body": "<p>AirSaas, ce n'est pas seulement l'automatisation de votre flash report projet, mais aussi des fonctionnalités dont vous ne pourrez plus vous passer pour votre gouvernance projet.</p>" }, { "type": "feature-split", "title": "Une vue macro pour <strong>simplifier</strong> votre planification stratégique", "body": "<p>Depuis AirSaas, visualisez en mode macro l'intégralité de votre portefeuille projet, et toutes les informations qui y sont liées : retards, météos, points d'attention, jalons…</p><p>Tout est à jour en temps réel et consolidé dans votre <em>roadmap</em> collaborative, pour assurer un pilotage optimal de votre portfolio, en fonction des urgences de vos équipes métiers et de vos décideurs business.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "timeline", "reversed": true }, { "type": "feature-split", "title": "Des vues personnalisables sur votre <strong>portefeuille de projets</strong>", "body": "<p>Si AirSaas n'est pas un outil de gestion de projets, il vous permet tout de même d'obtenir une visibilité plus précise sur vos projets, grâce à la vue liste, sur laquelle vous passez en revue l'avancée et les indicateurs de chaque projet.</p><p>Profitez également de la vue Kanban, qui vous permet d'analyser les états d'avancement de vos projets et leurs tendances générales, ainsi que de la vue timeline, sous forme de diagramme de Gantt, pour optimiser votre gestion des ressources et repérer les inter-dépendances de vos projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Portfolio projects kanban status", "reversed": false }, { "type": "feature-split", "title": "Vos fiches de cadrage de <strong>projet collaboratives</strong>", "body": "<p>Homogénéiser la culture projet de votre entreprise, et faites monter les chefs de projet en compétences, en leur proposant de remplir les fiches de cadrage de manière collaborative.</p><p>Grâce à AirSaas, vos projets partent sur le bon pied, pour être menés à bout, et aligner tout le monde sur une même méthodologie.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage de projet", "reversed": true }, { "type": "feature-split", "title": "L'outil collaboratif idéal pour <strong>mieux communiquer</strong>", "body": "<p>Paramétrez sur votre plateforme les notifications que vous voulez envoyer à vos équipes opérationnelles.</p><p>Un projet est à risque ? La période est terminée, et vous voulez en faire un bilan ? En quelques clics, envoyez ces messages-clés aisément, en les paramétrant à échéances fixes depuis AirSaas.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "People envolved", "reversed": false }, { "type": "intro", "title": "<strong>3 règles</strong> d'or pour utiliser votre flash report projet à bon escient", "body": "<p>AirSaas vous simplifie la tâche sur vos reportings projets. Mais n'oubliez pas d'appliquer les règles d'or suivantes pour en tirer le meilleur parti possible !</p>" }, { "type": "feature-split", "title": "<strong>Intégrez</strong> le ressenti de vos équipes à vos flash reports", "body": "<p>Présenter les métriques d'avancée de vos projets dans votre reporting, c'est bien. Mais y mettre en valeur le ressenti de vos équipes et de vos utilisateurs finaux dedans, c'est mieux ! Ce faisant, vous impliquez toutes les parties prenantes dans vos projets, et pouvez mettre en lumière les succès et les points d'attention qui ressortent de leur propre expérience. Parce qu'ensemble, on avance plus loin.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a7bb239ce496a6f00ac37f_metier-it.svg", "imageAlt": "équipes", "reversed": false }, { "type": "feature-split", "title": "Tenez-vous à une fréquence d'envoi de <strong>reporting fixe</strong>", "body": "<p>Votre flash report doit devenir un vrai rendez-vous pour toutes vos parties prenantes. Définissez la fréquence à laquelle vous le leur envoyez - nous vous recommandons un reporting mensuel, pour que chacun sache à tout moment où les projets en sont.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "reporting fixe", "reversed": true }, { "type": "feature-split", "title": "<strong>Envoyez vos reportings projets</strong> en amont du Copil", "body": "<p>Un Copil, ça se prépare - et pas seulement par vous ! Le fait d'envoyer en amont de la réunion votre reporting à tous les membres de votre Copil leur permet de se familiariser avec les décisions à prendre avant le jour J. Résultat : vous gagnez du temps pendant la réunion, et tout le monde est aligné autour d'un support de présentation connu de tous.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "Envoyez vos reportings projets", "reversed": false }, { "type": "testimonials", "title": "", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou .Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)" }] }, { "type": "cta", "title": "Faites passer <strong>votre gouvernance projet</strong> à la vitesse supérieure", "body": "<p>Choisissez une solution PPM collaborative et moderne, qui simplifie votre flash report et accélère vos prises de décisions.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "gestion-portefeuille-projet", "type": "solution", "meta": { "title": "L'outil de gestion de portefeuille projet nouvelle génération | AirSaas", "description": "La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les problèmes les plus fréquents en gestion de portefeuille de projets. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches." }, "sections": [{ "type": "hero", "title": "L'outil de gestion de portefeuille projet nouvelle génération", "body": "<p>La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/gestion-de-portefeuille-projet-pme\">problèmes les plus fréquents en gestion de portefeuille de projets</a>. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)" }] }, { "type": "intro", "title": "L'outil de portefeuille projets préféré des DSI et directions générales", "body": "<p>De nombreux outils de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\">gestion de portefeuille projet</a> sont proposés sur le marché : en quoi AirSaas se différencie-il des outils existants ?</p>", "subSections": [{ "title": "Prise en main facile", "body": "Le portefeuille de projet le plus simple au monde. AirSaas est conçu pour être utilisé aussi bien par les équipes IT que par les responsables métiers, sans aucune formation. Invitez vos collaborateurs à profiter d'une interface ergonomique et au design épuré." }, { "title": "Portefeuille projet orienté valeur", "body": "Donnez à votre organe de gouvernance projet le meilleur dispositif de prise de décision. Le portfeuille de projets AirSaas permet de rassembler dans une vue synthétique la combinaison des indicateurs nécessaires à une prise de décision orientée par la valeur." }, { "title": "Sans changer vos outils préférés", "body": "Le portefeuille de projets ne doit pas vous contraindre à abandonner vos outils de gestion de projets préférés. AirSaas se connecte aux outils les plus populaires du marché (Jira, Azure devOps, Asana, etc.) pour faire remonter les informations essentielles à un pilotage macro de vos activités." }] }, { "type": "feature-split", "title": "Décidez de manière avisée en Copil grâce au tableau de bord", "headingLevel": 3, "body": "<p>La stratégie de l'entreprise est claire, l'organe de gouvernance projet est en place, il faut maintenant mettre à disposition des indicateurs pertinents et à jour pour prioriser les projets en fonction des urgences, gains potentiels, ressources accessibles, etc.</p><p>La performance de votre Copil dépend de votre capacité à prendre les bonnes décisions dans les bons délais. AirSaas vous donne accès à un <a href=\"https://www.airsaas.io/fr/solution/revue-de-portefeuille\">tableau de bord de votre portefeuille projet</a>. Vous pouvez utiliser les filtres pour trouver les projets sur lesquels vous devez concentrer vos efforts.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "title": "Améliorez l'efficacité du reporting sur les projets en cours", "headingLevel": 3, "body": "<p>L'importance d'un bon reporting n'est plus à prouver. Plus les dirigeants et le management de l'entreprise est au courant de l'avancée des différents projets, plus les frustrations diverses disparaissent. Le problème est que le processus de collecte des informations nécessaire à ce reporting est une tâche chronophage pour vos collaborateurs.</p><p>C'est pour cela que nous vous proposons le rapport flash automatique. Générez une présentation (.ppt, .pdf, url) en un clic, avec l'ensemble des données à jour mises en forme dans des slides aux couleurs de votre entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Optimisez les ressources humaines disponibles", "headingLevel": 3, "body": "<p>Chaque vue du portefeuille de projets vous apporte des connaissances différentes. La timeline donne une vision d'ensemble des projets avec leurs jalons associés. Vous pouvez en un clin d'oeil appercevoir les dépassements, les dépendances, et les projets à mener en parallèle.</p><p>Envisagez différents scénarios en déplaçant les projets dans le temps et choissez la stratégie apportant le plus grand bénéfice. L'outil vous affichera des recommandations en fonction de différents facteurs (disponibilité des ressources, importance du projet, retard sur des jalons importants, etc.)</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Optimisation des ressources disponibles" }, { "type": "feature-split", "title": "Observez la consommation de vos ressources et de votre budget", "headingLevel": 3, "body": "<p>Le suivi des budgets et l'optimisation des ressources est clé dans le métier de DSI. C'est la combinaison à suivre en continu pour piloter ses activités.</p><p>AirSaas récupère les temps et budgets consommés grâce à ses connecteurs avec vos outils financiers et de gestion de projets. D'autre part, un module de déclaration est accessible pour avoir des informations à jour, consolidées et exportables.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd47790f0e45_outil3.svg", "imageAlt": "Pilotage budgétaire", "reversed": true }, { "type": "intro", "title": "Avancez plus sereinement avec votre équipe", "subSections": [{ "title": "Diminuez la frustration entre les métiers et l'IT", "body": "Vos équipes se plaignent du manque d'engagement des métiers sur les projets demandés. Et du côté des métiers, la frustration se ressent sur les retards et la non-prise en compte de leurs demandes. AirSaas propose un structure commune à suivre pour la mise en place d'un projet. La vue dashboard permet une compréhension partagée des contraintes de développement et une prise de décision collégiale par l'organe de gouvernance. L'outil place le collaboratif au premier plan et permet de faire remonter les problèmes rencontrés, les succès du parcours, partager les compte-rendus de réunions, etc. pour impliquer les équipes autour d'un intérêt commun." }, { "title": "Vers un meilleur cadrage des projets", "body": "Une mauvaise définition du projet est souvent la première source de frustration des équipes IT, et toujours l'une des raisons principales de retard de livraison du projet. Sur AirSaas, les utilisateurs sont accompagnés à se poser les bonnes questions et remplir les informations clés à un bon cadrage (gains espérés, critères de réussite, efforts à fournir, etc.). Ensuite, gardons en tête que le remplissage peut se faire de façon collaborative et asynchrone jusqu'au moment où le projet peut passer à l'état \"prêt à valider\" et être présenté au comité de pilotage." }, { "title": "Des équipes plus engagées autour d'un objectif clair", "body": "Mesurer régulièrement le degré de confiance dans le succès du projet auprès des équipes est essentiel. Ainsi vous pourrez rectifier le tir avant que l'échec annoncé ne devienne trop coûteux pour l'entreprise. Sur AirSaas, vous pouvez envoyer un sondage à intervalle régulier, et ainsi améliorer l'engagement des équipes en écoutant leur préoccupations et en fluidifiant la collaboration entre les métiers et l'IT." }, { "title": "Communiquez sur les avancées", "body": "Le contenu de votre plan de communication doit permettre aux responsables métiers et à votre direction de comprendre l'état d'avancement général, les points bloquants et les risques de glissement. Il doit aussi valoriser les succès pour motiver les équipes et inciter les récalcitrants à rejoindre le mouvement des projets qui réussissent. Le reporting est souvent considéré comme une activité chronophage. AirSaas vous aide dans ce processus en vous permettant de générer automatiquement vos rapports flash à envoyer en un clic." }] }, { "type": "intro", "title": "Une distinction à faire : différencier les outils de gestion de projet et de gestion de portefeuille de projet", "body": "<p>De nombreuses personnes assimilent les outils de gestion de projets aux outils de gestion de portefeuille de projet. Pourtant, ces deux types d'outils ne servent pas les mêmes objectifs.</p><p>Mais alors quelle est la différence entre ces deux typologies de logiciels ?</p>", "subSections": [{ "title": "La gestion de projet", "body": "<p>L'outil de gestion de projet vise à assurer le pilotage optimal d'un projet en particulier. Souvent grâce à un tableau de bord, il va simplifier différentes tâches :</p><ul><li>Le suivi de la réalisation des objectifs du projet</li><li>Le contrôle des délais des tâches assignées aux membres de l'équipe du projet</li><li>L'organisation et l'optimisation de la réalisation de chaque phase du projet</li><li>Le fait de garder une visibilité sur le déroulement du projet sous tous ses aspects</li><li>L'implication et l'engagement de chaque collaborateur sur le projet</li></ul>" }, { "title": "La gestion d'un portefeuille de projets", "body": "<p>Contrairement à l'outil de gestion de projet, la mise en place d'outil de gestion de portefeuille de projets permet d'optimiser l'exécution de plusieurs projets simultanément.</p><p>A mesure qu'elle se développe, une société est amenée à mener de plus en plus de projets en même temps. Si une bonne communication et une organisation structurée peuvent suffire pour diriger quelques projets conjointement, il arrive forcément un moment où la mise en place d'outil de gestion d'un portefeuille de projets devient un allié incontournable pour garder une efficience opérationnelle.</p><p>Pour résumer, à quoi sert un outil de gestion d'un portefeuille de projets ? Il permet notamment :</p><ul><li>de hiérarchiser les différents projets en fonction de leur priorité</li><li>d'assurer une visibilité optimale sur l'ensemble des projets et leurs étapes</li><li>d'impliquer tous les responsables de projets via l'assignation d'objectifs</li><li>de faciliter la mise en place d'une méthodologie collaborative sur les projets tout en brisant les silos entre services/directions</li></ul>" }] }, { "type": "intro", "title": "Rapide historique des outils de gestion de portefeuille de projets", "subSections": [{ "title": "A quand remonte l'apparition des outils de gestion de portefeuilles de projets ?", "body": "<p>Si les premiers outils de pilotage de portefeuilles de projets ont été créés il y a une quarantaine d'années, on peut tout de même noter que de nouveaux logiciels continuent à faire leur apparition régulièrement.</p><p>Aujourd'hui, tous ces outils couvrent les besoins de gestion de portefeuille de projets, mais cela n'a pas toujours été le cas ! En effet, certains d'entre eux ont initialement été créés pour permettre la gestion de projets.</p>" }, { "title": "Quelle était la première problématique ciblée : la gestion de projet ou la gestion de portefeuille de projets ?", "body": "<p>En regardant ce graphique, on peut se rendre compte que plus de la moitié des outils de gestion de portefeuilles de projets ont en fait initialement été pensés pour répondre aux besoins de gestion de projet. Ce n'est qu'ensuite que ces derniers ont été complétés afin de couvrir les deux problématiques en même temps : la gestion de projet et la gestion de portefeuilles de projets.</p><p>Il faut tout de même remarquer que certains de ces outils avaient été développés pour répondre à ces deux besoins (Sciforma, Ganttic) et que Planview était même axé dès son origine sur la gestion d'un portefeuille de projets. Aujourd'hui, il est très rare de rencontrer un outil qui ne couvre pas les deux aspects simultanément.</p>" }] }, { "type": "intro", "title": "Des visions différentes du pilotage de projet : l'exemple des DSI", "body": "<p>Une des raisons pour laquelle les logiciels de gestion de portefeuilles de projets ne proposent pas tous les mêmes fonctionnalités : cela dépend de la manière dont ils ont été pensés historiquement, mais c'est aussi une conséquence de la vision de la gestion de projets qu'ils défendent.</p><p>Mais pourquoi existe-il différentes visions de la gestion de projet dans les DSI ?</p>", "subSections": [{ "title": "La gestion de portefeuille : d'une mission centrée technique à une mission centrée business", "body": "<p>Le rôle de la DSI a fortement évolué dans les dernières décennies. D'une direction axée principalement sur la technique, elle est aujourd'hui bien plus impliquée dans la résolution des besoins business métiers. En plus de l'obligation d'assurer le fonctionnement opérationnel des systèmes d'information et du site de l'entreprise, on attend maintenant de la DSI qu'elle soit créatrice de valeur pour son organisation.</p><p>La nature de leurs projets ayant évolué, les attentes des DSI en matière de gestion de portefeuilles de projets ont donc progressivement évolué eux aussi : elles ont toujours besoin d'un outil permettant d'assurer la gestion des missions techniques, mais aussi d'un logiciel qui simplifie leur collaboration avec les métiers, et l'exécution des projets qu'ils ont en commun.</p>" }, { "title": "L'essor du digital : un vecteur de changement des besoins des DSI en gestion de portefeuille projets", "body": "<p>L'avènement du digital offre la possibilité aux DSI d'accompagner leur entreprise différemment, et notamment en pesant davantage dans l'exécution des objectifs business. Une DSI qui digitalise les workflows des métiers leur apporte aujourd'hui énormément en simplifiant leur quotidien et en optimisant leur efficacité. La DSI peut même aider une entreprise à changer de business model en l'accompagnant dans la mise en place de nouveaux services en ligne.</p><p>L'essor du digital a donc structurellement amené la DSI à se voir confier davantage de missions, de nature parfois très éloignée du simple maintien des systèmes d'information.</p>" }, { "title": "D'une DSI axée sur le contrôle des process à une DSI collaborant étroitement avec les métiers", "body": "<p>Les transformations décrites précédemment amènent forcément un changement dans la façon dont la DSI va interagir avec les collaborateurs de son entreprise. En effet, une DSI axée principalement sur des missions techniques aura plus tendance à essayer de garder sous contrôle le comportement des différents utilisateurs des systèmes d'informations. Alors qu'une DSI qui souhaite apporter de la valeur dans le coeur de métier de ses collaborateurs aura besoin de développer une relation plus étroite avec ces derniers.</p><p>Ainsi, en fonction de la mission que se donne la DSI, cette dernière n'aura pas besoin du même type d'outil de gestion de portefeuilles de projets.</p>" }] }, { "type": "intro", "title": "Des visions opposées de la gestion de portefeuille de projets qui amènent à la mise en place d'outils différents", "body": "<p>Une fois que l'on a compris que les outils de gestion de portefeuille de projets n'offrent pas tous les mêmes fonctionnalités, il faut s'interroger : quel est le type d'outil permettra d'atteindre les objectifs de sa DSI ?</p>", "subSections": [{ "title": "Des outils de gestion de portefeuille de projets variés selon les besoins de sa DSI", "body": "<p>Bien sûr, il existe des outils de pilotage de portefeuille de projet plus ou moins complets, proposant des fonctionnalités variées comme :</p><ul><li>La gestion des ressources</li><li>Le contrôle budgétaire</li><li>La gestion des risques</li><li>L'animation des instances des différents projets</li><li>La centralisation de toutes les informations essentielles</li><li>Le pilotage de la rentabilité des projets</li><li>La construction d'une communication efficiente entre équipes</li></ul>" }, { "title": "Les outils de gestion de portefeuilles de projets all-in-one VS ceux qui s'intègrent aux outils existants", "body": "<p>Certains outils de gestion de portefeuille de projets comme les ERP essayent de répondre à l'ensemble des besoins que peuvent avoir les DSI. S'ils sont souvent efficaces, il faut reconnaître qu'ils manquent toutefois de flexibilité une fois mis en place.</p><p>A l'inverse, d'autres outils (notamment ceux en mode SaaS) proposent moins de fonctionnalités mais ont la capacité de s'intégrer aux outils déjà installés. Opter pour ce genre de solutions permet d'éviter les doublons, et surtout de réduire le coût de change de son outil.</p>" }, { "title": "Les outils de gestion d'un portefeuille de projets avec un espace collaboratif structuré", "body": "<p>Dans le cas où le DSI souhaiterait instaurer une collaboration plus poussée avec les métiers de son entreprise, il peut être très intéressant pour lui d'opter pour la mise en place d'un outil comprenant un espace collaboratif. En effet, cet espace va permettre de structurer les échanges et de centraliser les informations importantes bien plus efficacement que sur des logiciels comme Slack ou Teams.</p>" }, { "title": "Les outils de gestion de portefeuille de projets qui misent sur l'UX", "body": "<p>Les logiciels de gestion d'un portefeuille de projets qui ont été développés pour fournir une expérience utilisateur de haute qualité présentent deux avantages majeurs pour une DSI.</p><p>Tout d'abord, il est bien plus facile de réussir à impliquer les métiers lorsqu'on leur propose un outil avec une interface intuitive. L'autre avantage majeur se situe au niveau du taux d'adoption du logiciel de portefeuille de projets : les outils misant sur l'UX offrent une prise en main rapide et sans trop de friction aux métiers.</p>" }, { "title": "Choisir son outil en fonction des méthodes de travail déjà installées", "body": "<p>Tous les outils portent une méthodologie en eux. Ainsi, une des astuces pour optimiser le taux d'adoption d'un nouveau logiciel dans son entreprise est de porter son choix vers la mise en place d'un outil avec une méthodologie intrinsèque proche de celle de son entreprise.</p><p>Il est donc indispensable de se questionner sur les pratiques existantes, pour choisir son outil de gestion d'un portefeuille de projets en fonction.</p>" }, { "title": "L'interface utilisateur comme vecteur de changement de la culture d'une entreprise", "body": "<p>Il est bien sûr conseillé de porter son choix sur la mise en place d'outil qui porte une méthodologie assez proche des process déjà existants dans votre entreprise. Mais il faut aussi noter qu'un outil d'un portefeuille de projets peut aussi faciliter l'implémentation de nouvelles méthodes de travail, ainsi que la changement progressif de la culture de l'entreprise.</p><p><strong>Pour résumer : choisissez un outil dont la méthodologie intrinsèque n'est pas trop éloignée de la réalité de votre entreprise ou, à défaut, de celle que vous souhaitez installer.</strong></p>" }] }, { "type": "intro", "title": "Où se situe AirSaas dans le spectre de tous ces outils de gestion de portefeuille de projets ?", "body": "<p>AirSaas est un outil de gestion de portefeuilles projets plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités clés dont une DSI a besoin pour assurer l'exécution de ses projets.</p>", "subSections": [{ "title": "Un outil PPM intuitif et intégré à vos outils existant", "body": "<p><strong>Jira</strong><br/>En s'intégrant à Jira, AirSaas vous permet d'obtenir automatiquement les données d'avancement des projets sur la plateforme. Cela vous permettra d'avoir une vue globale de l'ensemble des projets et de leurs états d'avancement sans efforts.</p><p><strong>Microsoft Teams</strong><br/>AirSaas est intégré à Microsoft Teams. Les informations les plus importantes sur les projets en cours seront envoyées automatiquement sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pourrez partager simplement l'avancée des projets avec l'ensemble de l'entreprise. Si vous utilisez d'autres solutions n'hésitez pas à nous le dire !</p>" }, { "title": "Un outil PPM avec une UX forte", "body": "<p>Notre pari : pour parvenir à impliquer les métiers, la DSI a besoin de l'<a href=\"/fr/solution/outil-ppm\">outil PPM</a> qu'ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n'est pas en forçant les métiers à travailler sur des logiciels complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.</p>" }, { "title": "Un outil PPM portant une méthodologie collaborative pour impliquer les métiers", "body": "<p>Nous avons poussé la logique collaborative jusqu'au bout : AirSaas propose un moteur de recherche de solutions (externes/internes) accessibles aux responsables métiers. Lorsqu'un métier a un besoin, il cherche déjà des solutions de son côté sans forcément prévenir la DSI qui peut même finir par se retrouver face à du Shadow IT.</p><p>Notre idée ici est de donner une solution à la DSI pour encadrer ces pratiques et structurer leurs efforts de recherche de solutions, tout en leur faisant comprendre les contraintes techniques du SI.</p><p><strong>AirSaas</strong> est donc solution PPM légère, qui s'intègre à l'existant, et qui porte une méthodologie collaborative forte afin d'impliquer les métiers.</p>" }] }, { "type": "cta", "title": "Découvrez comment AirSaas peut vous aider", "body": "<p>Adoptez dès maintenant une solution efficace de reporting projet.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "management-de-portefeuille-projet", "type": "solution", "meta": { "title": "L'outil de management de portefeuille projet qui révolutionne votre gouvernance", "description": "AirSaas a été conçu pour vous aider à transformer votre entreprise de manière efficace, en vous faisant gagner en temps et en visibilité sur votre portfolio. Révolutionnez votre management de portefeuille de projet en gardant une vision précise de vos priorités, des décisions à prendre, et en communiquant mieux au quotidien." }, "sections": [{ "type": "hero", "tag": "SOLUTION", "title": "L'outil de management de ", "titleHighlight": "portefeuille projet", "titleSuffix": " qui révolutionne votre gouvernance", "body": "<p>AirSaas a été conçu pour vous aider à transformer votre entreprise de manière efficace, en vous faisant gagner en temps et en visibilité sur votre portfolio. Révolutionnez votre management de portefeuille de projet en gardant une vision précise de vos priorités, des décisions à prendre, et en communiquant mieux au quotidien.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "La solution de portfolio project management favorite des <strong>PMO et DSI</strong>", "body": "<p>C'est parce que les outils traditionnels de gestion de portefeuille projet n'étaient pas adaptés aux besoins des professionnels de la transformation d'entreprise que nous avons conçu AirSaas.<br><br>À partir des retours de DSI et PMO, nous avons développé la plateforme collaborative de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\">management de portefeuille projet</a> la plus simple au monde : celle qui vous permet de visualiser aisément vos projets, de personnaliser vos tableaux de bord, et d'automatiser votre reporting en quelques clics seulement.<br><br>Fluide et simplissime, AirSaas accompagne désormais les Pro. de la Transfo. qui veulent <a href=\"https://www.airsaas.io/fr/gestion-de-projet/lean-portfolio-management\">accélérer leur prise de décision</a> et mener leurs projets plus loin, plus vite.</p>" }, { "type": "intro", "title": "<strong>Visualisez votre portfolio</strong> en vue macro", "body": "<p>Perdu dans les outils de gestion de projet traditionnels, qui vous empêchent de sortir du suivi micro des tâches de chaque projet ? Avec AirSaas, profitez d'une vue exhaustive multi-projets de tout ce qui compte pour assurer la gouvernance de votre portefeuille.</p>" }, { "type": "feature-split", "title": "Une <strong>planification stratégique simplifiée</strong> grâce à votre vue macro", "body": "<p>AirSaas vous permet d'accéder à un tableau de bord de portefeuille projet simple à lire, où toutes vos informations-clés sont rassemblées, consolidées, et à jour en temps réel.<br><br>Prenez de la hauteur sur votre portfolio de projets avec votre vue macro, et prenez des décisions plus rapides, alignées avec les véritables priorités stratégiques de votre entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "planification stratégique", "reversed": true }, { "type": "feature-split", "title": "Des <strong>intégrations natives</strong> pour limiter le report de données manuel", "body": "<p>Profitez de la marketplace d'intégrations natives d'AirSaas, qui synchronise votre plateforme PPM à vos outils préférés : gestion de tâches (Jira, ClickUp, Asana, Monday), communication interne (Microsoft Teams) et logiciel de service client (Zendesk).<br><br>Vos tableaux de bord se mettent à jour automatiquement et en temps réel avec les données qui comptent.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives", "reversed": false }, { "type": "intro", "title": "<strong>Concevez des vues personnalisées</strong> de votre tableau de bord", "body": "<p>Le management de projets demande parfois de pouvoir se focaliser sur les projets à risques ou qui viennent tout juste d'être lancés. Profitez des filtres personnalisables d'AirSaas, qui vous aide à visualiser votre portefeuille en fonction de la météo, des risques ou de l'avancement de vos projets.</p>" }, { "type": "feature-split", "title": "La vue <strong>liste</strong>", "body": "<p>Besoin de suivre l'avancée de vos projets, et de leurs indicateurs-clés ? Rendez-vous sur la vue liste, et passez en revue les différents projets de votre portefeuille aisément.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "List", "reversed": false }, { "type": "feature-split", "title": "La vue <strong>Kanban</strong>", "body": "<p>Pour observer les tendances générales de votre portfolio, choisissez la vue Kanban, et analysez les états d'avancement de vos projets. Rien de tel pour optimiser votre stratégie de pilotage !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Kanban", "reversed": true }, { "type": "feature-split", "title": "La vue <strong>timeline</strong>", "body": "<p>Cette vue sous forme de diagramme de Gantt est idéale pour optimiser votre gestion des ressources, anticiper les retards, et repérer en amont les dépendances inter-projets. Vous organisez vos projets sur le temps long, pour ne plus rien laisser au hasard.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Timeline", "reversed": false }, { "type": "cta-highlight", "title": "<strong>Boostez</strong> votre management de portefeuille projet et votre prise de décision", "body": "<p>Optez pour un outil PPM moderne et simple, où le collaboratif mène vos portefeuilles de projets plus loin, plus rapidement.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "<strong>Automatisez</strong> votre flash report", "body": "<p>Le Copil approche, et vous perdez un temps fou à récolter les données dont vous avez besoin auprès des chefs de projets, des métiers, et des différentes parties prenantes de vos projets ? Économisez ce temps grâce à la fonctionnalité de reporting automatisée d'AirSaas : elle vous fait gagner une journée de travail par semaine en moyenne.</p>" }, { "type": "feature-split", "title": "Votre <strong>reporting</strong>, véritable outil d'aide à la décision", "body": "<p>Avec le flash report automatisé d'AirSaas, vous permettez à chacun de visualiser aisément les décisions qui doivent être prises à l'instant T. Décisionnaires, chefs d'équipe et de projets, sponsors : tout le monde est aligné, pour fluidifier la prise de décision.<br><br>Dans votre reporting, vous transmettez les grandes lignes de vos projets (planning, timeline, KPI…), puis vous rentrez dans le détail des projets urgents. Jalons, risques, météos des projets, KPI d'avancement, ressources humaines et budgets impliqués, gains attendus… Tout ce dont vous avez besoin est là.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "la prise de décision", "reversed": false }, { "type": "feature-split", "title": "Une <strong>structure personnalisable</strong> et ultra-lisible", "body": "<p>En un clic sur AirSaas, créez votre flash report au format .pdf ou .ppt, et personnalisez-en le design selon la charte de votre entreprise. Vous pouvez également y ajouter des métriques-clés supplémentaires, des précisions sur vos plannings, ou encore un récapitulatif exhaustif des décisions à prendre.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "intro", "title": "<strong>Collaborez</strong> pour mieux transformer votre entreprise", "body": "<p>La gestion de votre portefeuille de projets nécessite une véritable collaboration entre vous, les métiers et les chefs de projet pour être optimale. Sur AirSaas, toutes les parties prenantes apportent leur pierre à l'édifice, depuis le cadrage des projets jusqu'à leur mise en œuvre quotidienne. Plus personne ne peut vous dire : \"Je ne savais pas !\"</p>" }, { "type": "feature-split", "title": "Des fiches de cadrage <strong>co-créées</strong>", "body": "<p>Impliquez chaque chef de projet dans le cadrage de vos projets, depuis la structure fixe AirSaas qui vous permet de définir un standard à votre culture projet. Cette méthodologie forte vous permet de faire démarrer chaque projet sur le bon pied.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage", "reversed": true }, { "type": "feature-split", "title": "Une <strong>communication fluide</strong> avec tous les acteurs de votre transformation", "body": "<p>Sur AirSaas, notifiez automatiquement vos équipes opérationnelles quand un projet est à risque, et envoyez des bilans aisément. Tout est paramétrable à échéances fixes, selon les rituels que vous avez créé dans votre management de portefeuille de projet.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Communiquez", "reversed": false }, { "type": "feature-split", "title": "Des <strong>bilans de projet</strong> bien huilés", "body": "<p>Rien de tel qu'un bilan de projet pour faire le point, et tirer les bonnes pratiques et les points d'amélioration de votre culture projet. Créez l'engagement de chacun en générant des bilans de projets complets : coûts, délais, retours DAKI et engagement de vos équipes s'y retrouvent - et tout le monde en tire les bonnes conclusions.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "bilans de projet", "reversed": true }, { "type": "cta-highlight", "title": "Choisissez de <strong>gagner du temps</strong> et du contrôle", "body": "<p>Adoptez dès maintenant une solution de management de portefeuille projet efficace, à l'expérience utilisateur vraiment fluide.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "<strong>Les 5 règles</strong> d'or d'un bon management de portefeuille projet", "body": "<p>Il ne suffit pas de déployer un bon outil de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/project-portfolio-management\">portfolio project management</a> pour assurer une gouvernance optimale à votre transformation d'entreprise. Suivez les cinq règles d'or suivantes pour structurer votre démarche, et décupler votre succès.</p>" }, { "type": "feature-split", "title": "Réduire <strong>la durée des projets</strong> dans votre portefeuille", "body": "<p>Notre position : un projet ne devrait pas dépasser les trois mois. Les projets longs créent le chaos dans les équipes, qui perdent en engagement avec le temps - et bien souvent, ils ne voient jamais le jour.<br><br>Pour faire en sorte que chaque projet dure trois mois maximum, segmentez vos projets plus longs en plusieurs grandes phases de trois mois chacune. Ainsi, vous motivez toutes les parties prenantes, et vous assurez d'un pilotage des projets optimal.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659c49b1c11c7db42bdbe382_portfolio1-min.svg", "imageAlt": "indicateurs de performance", "reversed": false }, { "type": "feature-split", "title": "Définir un <strong>ordre d'exécution</strong> des différents projets", "body": "<p>Pour bien piloter votre portefeuille de projet, tout commence par une bonne définition des priorités à accorder à chacun de vos projets. Or, bien souvent, pour la direction, la plupart des projets sont hautement prioritaires : difficile alors de prioriser au quotidien dans votre gouvernance !<br><br>Pour pallier ce souci, définissez un ordre d'exécution des différents projets : lequel vient en premier, puis en deuxième, puis en troisième ?<br><br>Veillez également à éviter de toujours retenir l'avis de la personne la plus haut placée hiérarchiquement dans l'entreprise. Vous pouvez par exemple lui faire donner son avis en dernier lors des tours de table de votre comité de pilotage, pour pouvoir entendre tous les avis, et ne pas favoriser les projets d'une seule et même personne.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d740ad0d75cbc3c06eba7f_Project%20page%20zoom%20importance-risk.webp", "imageAlt": "Project page importance-risk", "reversed": true }, { "type": "feature-split", "title": "Privilégier <strong>l'achèvement de projets</strong> en cours que le lancement de nouveaux projets", "body": "<p>Plus vous disposez de projets simultanés dans votre portefeuille, plus il est difficile de les finaliser rapidement. Ainsi, on observe <a href=\"https://www.airsaas.io/fr/gestion-de-projet/les-10-erreurs-a-ne-pas-commettre-dans-la-mise-en-place-dun-portefeuille-projet\">bon nombre d'entreprises lancer un grand nombre de projets</a>, sans jamais les voir s'achever. Privilégier un plus petit nombre de projets à la fois vous permet d'en observer plus rapidement la valeur générée.<br><br>Cette règle d'or demande donc de bien savoir prioriser les projets à lancer en premier. Focalisez-vous sur ceux qui apporteront en premier une véritable valeur ajoutée à votre organisation. Une réflexion, certes subjective, mais qui vous permettra de tirer le plus de ROI de votre management de portefeuille projet !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Portfolio projects kanban status", "reversed": false }, { "type": "feature-split", "title": "<strong>Ritualiser</strong> votre portfolio project management", "body": "<p>Un rituel est un ensemble des règles et habitudes fixées - et c'est là l'une clé de votre transformation culturelle réussie. Votre objectif ? Développer de nouvelles habitudes de décisions, communication et coopération, de la journée à l'année, dans vos équipes.<br><br>Organisez dans le temps, à intervalles réguliers, vos <a href=\"https://www.airsaas.io/fr/solution/revue-de-portefeuille\">revues de portefeuille stratégique</a>, votre budgétisation participative, ou encore vos réunions de synchronisation du portefeuille. Et tenez-vous-y : la régularité est l'une des clés du succès de l'alignement autour de ces rituels de gouvernance.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659446696cfdb8c043b15796_calendar_illustration.svg", "imageAlt": "indicateurs limpides", "reversed": true }, { "type": "feature-split", "title": "Renforcer <strong>la culture projet</strong> dans votre entreprise", "body": "<p>Votre <a href=\"https://www.airsaas.io/fr/solution/outil-ppm\">outil PPM</a> vous permet d'expliquer à chacun, à même la plateforme, quels sont leurs rôles, comment mieux cadrer des projets en amont, ou encore comment bien communiquer sur les besoins de chaque projet. Cependant, en tant que PMO ou DSI, votre rôle suppose également de promouvoir une véritable culture portfolio project management pragmatique au quotidien.<br><br>Pour cela, définissez trois à sept principes d'action à votre management de portefeuille projet. Par exemple, vous pouvez y promouvoir la sincérité, l'auto-organisation, l'empathie et la confiance, la transparence, ou encore la coopération gagnant-gagnant. Ainsi, chacun est aligné autour de ces grands principes, et reste motivé à tout moment.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a6a9328dd6d654d8262628_PMO-DSI.svg", "imageAlt": "les métiers", "reversed": false }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou .Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp" }] }] }, { "slug": "outil-ppm", "type": "solution", "meta": { "title": "AirSaas : un outil PPM nouvelle génération - Logiciel PPM", "description": "Souvent complexes et coûteux à implémenter, AirSaas propose un outil PPM nouvelle génération. Finissez-en aujourd'hui avec votre Excel à 1200 colonnes !" }, "sections": [{ "type": "hero", "title": "AirSaas : un outil PPM nouvelle génération - Logiciel ppm", "body": "<p>Souvent complexes et coûteux à implémenter, AirSaas propose un outil PPM nouvelle génération. Finissez-en aujourd'hui avec votre Excel à 1200 colonnes !</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "Quels sont les meilleurs logiciels PPM ? L'exemple AirSaas", "body": "<p>Un outil PPM (<a href=\"https://www.airsaas.io/fr/gestion-de-projet/project-portfolio-management\">Project Portfolio Management</a>), permet de donner de la visibilité aux managers et de prioriser les projets en fonction des retombées potentielles pour l'entreprise.</p>" }, { "type": "intro", "title": "Enfin l'outil PPM que toutes les Directions attendaient", "subSections": [{ "title": "Simplissime", "body": "Fini les 5 jours de formation, importez votre Excel, invitez votre équipe et c'est parti. L'interface est ergonomique et intuitive, la prise en main se fait dés le premier jour." }, { "title": "PPM orienté valeur", "body": "Un PPM ne doit pas simplement vous aider à mieux <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\">piloter vos projets</a>, il doit vous permettre d'apporter plus de valeur à l'entreprise. AirSaas vous permet de suivre les indicateurs essentiels et mesurer le retour sur investissement de vos actions." }, { "title": "Connecté à vos outils du quotidien", "body": "Dans un monde où les outils se multiplient, il est essentiel de ne pas avoir à ressaisir l'information d'un outil à l'autre ou de chercher le document partagé de partout. AirSaas se connecte à vos outils de communication, de finance, de développement, pour simplifier le quotidien de tout le monde dans l'entreprise." }] }, { "type": "feature-split", "title": "Prenez des décisions avisées en Copil", "body": "<p>Pour prendre les bonnes décisions il faut les bonnes informations en entrée, à jour et consolidées. La performance de votre activité dépend de votre capacité à être efficace dans la gestion de vos comités de pilotage.<br/>‍<br/>AirSaas vous fourni un tableau de bord de tous vos projets, filtrable suivant les indicateurs essentiels, permettant de ne voir que les informations importantes à la prise de décision.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": false }, { "type": "feature-split", "title": "Gagnez du temps en reporting", "body": "<p>Vos équipes reçoivent régulièrement des questions sur l'état d'avancement des projets, le manager passe beaucoup de temps à remplir des slides Powerpoint en glanant les informations à gauche et à droite.<br/><br/>Nous avons créé pour vous le <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">rapport flash</a>. En un clic une présentation (.ppt, .pdf, url) est générée, contenant les slides projet avec toutes les données à jour. Vous pouvez maintenant tenir au courant la direction générale et les responsables métiers de l'avancée de vos activités, des ressources humaines mobilisées, etc.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting flash avec votre logiciel PPM", "reversed": true }, { "type": "feature-split", "title": "Améliorez votre gestion des ressources", "body": "<p>La vue timeline vous permet d'avoir une <a href=\"https://www.airsaas.io/fr/gestion-de-projet/capacity-planning\">vision d'ensemble des projets</a> en cours et leurs jalons associés. Vous pouvez déplacer les éléments grâce au cliquer-glisser et envisager des nouveaux scénarios. Assurez-vous de la disponibilité des ressources et priorisez les projets par importance, solution ou logiciel choisi, évaluation de l'importance pour le métier, etc.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Gestion des ressources depuis votre outil PPM", "reversed": false }, { "type": "feature-split", "title": "Suivez la consommation des budgets et des ressources", "body": "<p>Vous ne pouvez pas être pris au dépourvu, vous devez surveiller la consommation de vos budgets et de vos ressources en continu. Pour cela, AirSaas se connecte à vos outils de développement pour récupérer les jours homme consommés et vos outils financiers pour les budgets consommés. L'objectif est de vous fournir une vue consolidée et exportable.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d705feadffd7e3d62baec2_Project%20page%20effort%20and%20budget%20consumed.webp", "imageAlt": "Project page effort and budget consumed", "reversed": true }, { "type": "intro", "title": "Faites avancer les projets sereinement", "subSections": [{ "title": "Fluidifiez les relations entre l'IT et les métiers", "body": "Les métiers reprochent la lenteur du département IT et la non prise en compte de leurs besoins. L'IT manque de ressources et reproche aux métiers leur manque d'investissement. AirSaas apporte un workflow commun et une vue consolidée permettant de mettre en avant les jeux de contrainte de chacun.<br/>AirSaas est collaboratif \"by design\" permettant de rassembler les parties prenantes autour d'un même outil, compréhensible de tous.<br/><br/>L'outil permet un reporting régulier, ainsi qu'une remontée des problèmes rencontrés et des succès du parcours pour engager les équipes et avancer sereinement." }, { "title": "Améliorez la phase de cadrage", "body": "Au menu, un cadrage guidé où les utilisateurs sont accompagnés pour remplir les informations essentielles au bon démarrage (gains espérés, critères de réussite, effort à fournir, etc.), auquel on ajoute la possibilité de les remplir de façon collaborative et asynchrone. Quand le niveau de remplissage est suffisant, le projet peut partir en validation au comité de pilotage." }, { "title": "Augmentez l'engagement des équipes", "body": "Envoyez un sondage régulier et anonyme aux membres de l'équipe pour sonder leur degré de confiance dans le succès du projet. Grâce à l'outil AirSaas, vous créez un lien de coopération entre l'IT et les métiers. Les métiers ne sont plus les clients de l'IT, et l'IT n'est plus au service des métiers. La mise en œuvre d'une collaboration saine est essentielle à la réussite des projets, tout au long de leur cycle de vie." }, { "title": "Partagez vos avancées", "body": "Le plan de communication est indispensable à la réussite de vos projets et de votre équipe. Tenez au courant les membres du Comex et les responsables métier pour diminuer la frustration, mettre en avant les succès et inciter d'autres collaborateurs à rejoindre le mouvement des projets qui fonctionnent. Une tâche qui normalement est chronophage, mais le rapport flash automatique va grandement vous aider !" }] }, { "type": "intro", "title": "Une erreur à éviter : confondre les PM et les PPM", "body": "<p>Il y a souvent une confusion entre les outils de PM (Project Management / gestion de projet) et les outils de PPM (Portefolio Project Management : gestion de portefeuille de projets), bien qu'ils n'aient pas les mêmes objectifs.<br/><br/>Commençons donc par différencier ces deux types d'outil de pilotage de projet.</p>" }, { "type": "feature-split", "title": "Le PM : outil de gestion de projet", "body": "<p>Le PM permet d'assurer la gestion d'un projet en particulier. Il va simplifier l'ensemble des missions du chef de projet :</p><ul><li>contrôle du respect des objectifs</li><li>gestion des délais de réalisation</li><li>optimisation de suivi des actions de chaque membre de l'équipe</li><li>planification de l'exécution de chaque phase de la gestion du projet</li><li>offrir une visibilité sur la gestion de l'ensemble du projet grâce à un tableau de bord</li><li>animer les équipes en charge de la gestion du projet</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65df5fc43b89570d447c3af6_Graphic-PM.webp", "imageAlt": "Le PM : outil de gestion de projet", "reversed": false }, { "type": "feature-split", "title": "Le PPM : outil de gestion de portefeuille de projets", "body": "<p>Là où le PM optimise la planification d'un projet en particulier, un outil PPM va permettre d'organiser tous les projets d'une organisation.<br/>Lorsqu'une entreprise évolue continuellement, elle arrive forcément à un stade où elle sera amenée à assurer la gestion de plusieurs projets en même temps. Et c'est justement lorsque ce nombre de projets commence à devenir important que les logiciels de gestion de portefeuille de projets deviennent indispensables.</p><ul><li>prioriser les projets</li><li>offrir une visibilité globale sur la gestion de projets</li><li>garantir une transparence sur la gestion du portefeuille de projet</li><li>responsabiliser les chefs de projets et leur assignant des objectifs</li><li>sortir des logiques de silos et installer une approche collaborative</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Portfolio projects list", "reversed": true }, { "type": "intro", "title": "Un bref retour historique sur les outils PPM", "subSections": [{ "title": "Quand est-ce que les logiciels ppm ont commencé à apparaître ?", "body": "Si les premiers outils de gestion de projet ont commencé à apparaître dès les années 80, on remarque tout de même que de nouvelles entreprises ont depuis continué de développer des logiciels concurrents. Une autre chose intéressante : si ces logiciels répondent aujourd'hui tous aux problématiques de gestion de portefeuilles de projets, chacun d'entre eux n'a pas initialement été développé pour servir les mêmes objectifs ! Certains priorisaient la gestion de projets, tandis que d'autres abordaient dès le début la gestion des portefeuilles de projets." }, { "title": "Quel besoin est apparu en premier : la gestion de projet ou de portefeuille de projets ?", "body": "On peut voir qu'une majorité des outils de gestion de portefeuille projets ont en fait commencé par proposer des services de gestion de projet ! Ce n'est que par la suite, que ces derniers ont été complétés afin de permettre de mener plusieurs projets de front de manière optimale." }] }, { "type": "intro", "body": "<p>On peut quand même noter que des outils étaient axés dès le début sur la gestion de portefeuille projets (Planview), même si certains d'entre eux proposaient en parallèle des fonctions de gestion de projet (Sciforma, Ganttic).<br/><br/>Aujourd'hui, la quasi-totalité de ces logiciels répondent aux deux besoins : la gestion de projet et la gestion de portefeuille de projets. On constate donc bien qu'il existe une nécessité de fluidifier la prise de décision dans les entreprises, que ce soit à l'échelle de la gestion d'un projet, ou à une échelle plus globale à l'aide d'un outil PPM.</p>" }, { "type": "intro", "title": "Les différentes visions de la gestion de projet : l'exemple des DSI", "body": "<p>Si les logiciels de gestion de portefeuilles de projets ne présentent pas tous les mêmes fonctionnalités, c'est en partie dû à la manière dont ils ont été construits historiquement, mais c'est aussi une conséquence de la vision de la gestion de projets qu'ils défendent.<br/><br/>Mais pourquoi existe-t-il différentes visions de la gestion de projet dans les DSI ?</p>", "subSections": [{ "title": "La gestion de projet : d'un prisme technique à un prisme business", "body": "La plupart des livres blancs sur le sujet s'accordent à dire que dans les dernières décennies, la DSI est passée d'un rôle largement cantonné à un aspect technique à une mission centrée sur les besoins business des métiers. La DSI n'est plus réduite à assurer le fonctionnement du run, en fournissant une assistance purement technique, mais elle doit aussi comprendre les besoins des différents collaborateurs afin de leur apporter de la valeur dans leur coeur de métier.<br/><br/>Les attentes qu'ont les DSI d'un outil pour piloter leurs projets ont donc forcément énormément évoluées : d'un outil de suivi de gestion des problématiques techniques, les DSI ont souvent besoin que leur PPM simplifie la communication avec les métiers et la remontée de leurs besoins, notamment en passant par l'intermédiaire du chef de projet." }, { "title": "L'impact de l'essor du poids du digital sur les besoins des DSI en gestion de projets", "body": "Le développement du digital permet aux DSI d'aider leur entreprise de manière différente, et notamment en contribuant davantage à la réussite des objectifs business. Par exemple, une DSI peut structurer la digitalisation des process, ce qui entraîne des gains de temps pour les métiers et aide ces derniers à être compétitifs face aux entreprises concurrentes. Elle peut même participer à la création de valeur, notamment en accompagnant le changement de business modèle de l'entreprise. On peut aussi penser à l'anecdote de Pierre Raschi, DG de Référence DSI, où il raconte comment une DSI en temps partagé a permis à une boucherie de renouveler sa clientèle vieillissante grâce au digital.<br/><br/>Ce changement structurel du poids du digital pour une entreprise amène donc à confier davantage de missions à la DSI. Ainsi, puisque la DSI a de nouvelles responsabilités, elle pilote ses projets différemment, et attend donc de nouvelles fonctionnalités de la part de ses outils PPM, ce qui amène ces derniers à évoluer !" }, { "title": "Un changement de paradigme : du contrôle des process, à un besoin d'impliquer les collaborateurs", "body": "Les deux changements que l'on a vus ci-dessus impliquent une évolution dans la manière qu'a la DSI de collaborer avec les différents services et équipes de son entreprise. Une DSI axée sur la technique essayait plutôt de contrôler les comportements des collaborateurs afin qu'ils ne soient freinés par aucun problème technique et que le SI ne soit pas affecté négativement. Aujourd'hui, si elle veut réussir à impacter le business de l'entreprise de manière positive, la DSI doit être capable de comprendre finement les besoins des métiers et donc de collaborer étroitement avec ces derniers. Et une telle collaboration nécessite de briser les silos qui peuvent exister entre les services, ou au sein même des équipes, et d'impliquer chacun des collaborateurs. Ainsi, une DSI qui souhaite contrôler tous les processus existants n'aura pas besoin du même type d'outil que celle qui cherche à structurer une collaboration forte avec ses collaborateurs." }] }, { "type": "intro", "title": "Des visions opposées de la gestion de projets qui requièrent la mise en place de PPM différents", "body": "<p>Une fois que l'on a compris que les PPM ne répondaient pas tous aux mêmes besoins, il faut se poser une question : quel outil PPM va être adapté à ma vision du rôle de la DSI ainsi qu'à mes objectifs ?</p>", "subSections": [{ "title": "Des PPM variés selon les besoins de sa DSI", "body": "<p>Bien sûr, il existe des PPM qui proposent différentes fonctionnalités, plus ou moins poussées :</p><ul><li>arbitrage des projets</li><li>pilotage des ressources</li><li>construction budgétaire</li><li>gestion des risques</li><li>animation des instances projet</li><li>reporting des informations essentielles</li><li>contrôle de la rentabilité</li><li>espace de communication simplifié</li></ul><p>Mais au-delà de cette liste de fonctionnalités, il est possible de mettre en avant des styles de PPM opposés pour les différencier plus facilement.</p>" }, { "title": "Les PPM tout-en-un VS les PPM qui s'intègrent aux applications existantes", "body": "Certains PPM comme les ERP ambitionnent de répondre à tous les besoins des DSI sur un seul et même logiciel. Bon nombre d'entre eux sont efficaces, mais le manque de flexibilité d'une telle solution une fois implémentée oblige à prendre le temps de s'interroger avant de faire son choix.<br/><br/>A l'inverse, d'autres logiciels (souvent des SaaS) offrent moins de fonctionnalités mais proposent de s'intégrer aux outils existants. Ils permettront ainsi d'éviter les doublons et de diminuer le coût de change d'un outil : là où la montée de version d'un outil PPM lourd sera un projet majeur, long, et coûteux.<br/><br/>Ces deux types d'outils ne correspondent pas à la même vision du rôle de la DSI. Dans le cas des logiciels qui s'intègrent à l'existant, la DSI est perçue comme n'ayant plus à acquérir un outil lui permettant d'avancer sur tous les fronts, mais plutôt comme devant être capable de connecter et de déconnecter différents outils, en fonction de l'évolution de l'entreprise. L'idée est d'être en capacité de coller aux besoins existant, constamment, et à moindre coût." }, { "title": "Les PPM qui proposent un espace d'échange collaboratif", "body": "Selon la vision qu'aura le DSI de son rôle pour l'entreprise, un espace collaboratif incorporé directement dans son outil PPM peut vraiment simplifier son quotidien et celui de ses équipes. Si la plupart des entreprises utilisent déjà des canaux \"classiques\" pour faire remonter les besoins métiers à la DSI (Teams, Slack), faire le choix d'utiliser un PPM qui propose une interface d'échange plus structurée permet de centraliser l'information afin de collaborer plus efficacement." }, { "title": "Les PPM qui misent sur l'UX", "body": "L'avantage qu'amène le choix de ces PPM est double. Tout d'abord, si l'on souhaite impliquer les collaborateurs d'une entreprise sur des sujets aussi techniques que ceux traités par la DSI, mieux vaut le faire sur une interface qui leur plaira. Il n'y a rien de plus décourageant que d'être invité à travailler sur un Excel géant lorsque l'on n'est pas la personne ayant passé des dizaines d'heures à le créer. Les PPM qui misent sur l'UX ont donc généralement une interface suffisamment intuitive pour faciliter la collaboration entre les profils techniques et business.<br/><br/>Le second avantage est d'augmenter le taux d'adoption de ces PPM : les collaborateurs ne mettront que quelques heures à se roder à l'utilisation de ces nouveaux logiciels plutôt que quelques jours, ce qui peut être un levier très intéressant si l'objectif est de mobiliser rapidement." }, { "title": "L'importance d'adapter la méthodologie portée par l'outil à la réalité de son organisation", "body": "Aucun outil n'est réellement neutre, chacun d'entre eux porte intrinsèquement une méthodologie. Si l'on souhaite maximiser le taux d'adoption de son outil PPM, l'un des facteurs clé est d'en choisir un qui porte une méthodologie adaptée au fonctionnement de son organisation : aux niveaux des processus existants, des objectifs fixés, ou même de sa vision de la gestion de projets.<br/><br/>Prendre un outil PPM portant une méthodologie opposée à celle qui est en place serait aussi contre-productif que de nager à contre-courant. Ainsi, il est primordial de s'interroger sur la méthodologie que l'on souhaite appliquer, afin de choisir son outil PPM en conséquence." }, { "title": "Changer la culture d'une entreprise grâce à l'interface utilisateur", "body": "S'il vaut mieux adopter un outil dont la méthodologie est proche de la réalité de votre fonctionnement, un outil PPM peut aussi être un levier pour faire évoluer vos méthodes de travail ainsi que la culture de votre entreprise. En effet, la culture d'une entreprise est le fruit du comportement qu'elle adopte face à un environnement particulier. Donc si l'on change l'environnement, notamment en changeant les logiciels utilisés, on change la culture !<br/><br/>Il est donc possible de se servir d'un nouvel outil pour impulser un changement de pratiques. Cependant, il faut tout de même veiller à ce que le changement souhaité ne soit pas à l'opposé de ce que vous promouvez actuellement. En effet, s'il n'est pas accompagné par des décisions et des directives allant dans le même sens, un outil à lui seul ne peut pas bousculer les habitudes ancrées dans une organisation." }] }, { "type": "intro", "title": "Où se situe AirSaas dans le spectre de tous ces outils de gestion de projet ?", "body": "<p>Comme décrit en haut de page, AirSaas est un outil de gestion de portefeuilles projets plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités clé dont une DSI a besoin pour assurer l'exécution de ses projets.</p>", "subSections": [{ "title": "Un outil PPM intuitif et intégré à vos outils existant", "body": "<p><strong>Jira</strong><br/><br/>En s'intégrant à Jira vous aurez automatiquement les données d'avancement des projets dans AirSaas. Cela vous permettra d'avoir une vue globale de l'ensemble des projets et de leurs états d'avancement sans efforts.</p><p><strong>Microsoft Teams</strong><br/><br/>AirSaas est intégré à Microsoft Teams. Automatiquement les informations les plus importantes sur les projets en cours seront envoyées sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pourrez partager simplement l'avancée des projets avec l'ensemble de l'entreprise. Si vous utilisez d'autres solutions, n'hésitez pas à nous le dire !</p>" }] }, { "type": "feature-split", "title": "Un outil PPM avec une UX forte", "body": "<p>Notre pari : pour parvenir à impliquer les métiers, la DSI a besoin de le outil PPM qu'ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n'est pas en forçant les métiers à travailler sur des outils complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70979f3aaee0cbfd859cc_Feed%20search%20solution.webp", "imageAlt": "Un outil PPM avec une UX forte", "reversed": true }, { "type": "intro", "title": "Un outil PPM portant une méthodologie collaborative pour impliquer les métiers", "body": "<p>Nous avons poussé la logique collaborative jusqu'au bout : AirSaas propose un moteur de recherche de solutions (externes/internes) accessibles aux responsables métiers.<br/>Lorsqu'un métier à un besoin, il cherche déjà des solutions de son côté sans forcément prévenir la DSI qui peut même finir par se retrouver face à du Shadow IT.<br/><br/>Notre idée ici est de donner une solution à la DSI pour encadrer ces pratiques et structurer leurs efforts de recherche de solutions, tout en leur faisant comprendre les contraintes techniques du SI.</p><p><strong>AirSaas</strong> est donc solution PPM légère, qui s'intègre à l'existant, et qui porte une méthodologie collaborative forte afin d'impliquer les métiers.</p>" }, { "type": "cta", "title": "AirSaas : le logiciel PPM nouvelle génération", "body": "<p>N'hésitez pas à bénéficier de la version gratuite de AirSaas.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "outils-de-pilotage-projet", "type": "solution", "meta": { "title": "Une nouvelle manière de voir les outils de pilotage projet - AirSaas", "description": "Parce que la gestion ne se résume pas à un Gantt, AirSaas propose un outil de pilotage de projet qui simplifie votre reporting, votre gouvernance et votre communication projet." }, "sections": [{ "type": "hero", "title": "Une nouvelle manière de voir les outils de pilotage projet - AirSaas", "body": "<p>Parce que la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\">gestion</a> ne se résume pas à un Gantt, AirSaas propose un outil de pilotage de projet qui simplifie votre reporting, votre gouvernance et votre communication projet.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "Nous proposons l'outil de pilotage de projet <strong>le plus simple au monde.</strong>", "body": "<p>Les outils de pilotage de projet permettent de donner de la visibilité aux managers et de leur offrir la faculté de hiérarchiser efficacement les projets en fonction des retombées potentielles pour l'entreprise.</p>", "subSections": [{ "title": "Ultra simple", "body": "AirSaas ne demande aucun setup : importez votre Excel et commencer à utiliser l'outil. Pas de formation nécessaire, l'outil est utilisable par votre équipe projet dès le premier jour." }, { "title": "3x moins cher que les outils du marché", "body": "Le prix ne doit pas être un frein à votre productivité. Profitez d'une période d'essai gratuite et payez ensuite un abonnement en fonction du nombre d'utilisateurs." }, { "title": "A partir de 10 projets", "body": "AirSaas vous fait gagner en visibilité et rend vos équipes plus productives quelle que soit la taille de votre DSI. N'attendez pas d'être débordé pour vous équiper." }] }, { "type": "feature-split", "title": "Accompagnez le cadrage des projets", "body": "<p>Un bon projet est un projet bien préparé. Pourtant, 90% des fiches de cadrage sont incomplètes. Sur AirSaas, nous guidons vos collaborateurs dans le remplissage des informations essentielles à un bon cadrage.<br/>Les fiches de cadrage sont dynamiques et collaboratives. Vos équipes peuvent itérer ensemble jusqu'à que le projet soit validé.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d473f144eace1121240b18_Modal%20-%20create%20project.webp", "imageAlt": "cadrage de projet", "reversed": false }, { "type": "feature-split", "title": "Le pilotage de projet <strong>par la valeur</strong>", "body": "<p>Tous les projets ne se valent pas. En tant que partenaire business, vous devez proposer une méthode pour <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">piloter les projets IT</a> suivant des indicateurs-clés.<br/>AirSaas propose une vue filtrable avec toutes les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">informations consolidées</a> pour prendre des décisions avisées.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d72da0c3898a0380300909_Portfolio%20project%20filter%20open.webp", "imageAlt": "Pilotage de projet", "reversed": true }, { "type": "feature-split", "title": "Reportez en un clic", "body": "<p>Vous êtes au centre des attentions et devez tenir au courant les responsables métiers et votre direction de l'avancée des projets. Pour cela, nous avons créé les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">rapports flash automatisés</a>.<br/>En un clic, générez un <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-gestion-de-projet\">rapport</a> (.ppt, .pdf, url) avec les détails d'avancée des projets, les points d'attention et tous les indicateurs à jour.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash", "reversed": false }, { "type": "feature-split", "title": "Prenez de la hauteur", "body": "<p>Rien ne vous échappe grâce à la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/macro-planning\">vue timeline</a>. Prenez de la hauteur et profitez d'un panorama sur tous les projets en cours et leurs jalons associés.<br/>Déplacez les éléments grâce au cliquer-glisser et testez des nouveaux arrangements en fonction des disponibilités des parties prenantes et de l'urgence des projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Vue timeline macro", "reversed": true }, { "type": "intro", "title": "Valorisez le travail de votre équipe", "subSections": [{ "title": "Diminuez la friction avec les métiers", "body": "<p>Les principales frictions proviennent du manque de compréhension du jeu de contraintes de la DSI et de la prise en compte des attentes des métiers. Réunir les parties prenantes en <a href=\"https://www.airsaas.io/fr/gestion-de-projet/copil-projet-ou-comite-de-pilotage-projet-les-bases\">comité de pilotage</a>, autour d'un dashboard affichant les indicateurs-clés, améliore la compréhension de ce qui peut être fait et dans quels délais.</p><p>Un workflow de décision clair et partagé aide à la compréhension en apportant de la transparence.</p><p>Et enfin, communiquer à intervalle régulier sur l'avancée, les problèmes rencontrés et les succès d'étapes aide à diminuer les frustrations et l'impatience des personnes en demande. Moins de friction permet à votre équipe d'avancer plus sereinement.</p>" }, { "title": "Augmentez le taux de réussite des projets IT", "body": "<p>Les principaux facteurs d'échec d'un projet sont le mauvais cadrage qui entraînent des dépassements de délais et de coûts, et le manque d'adoption des utilisateurs finaux (clients internes ou externes). Pour cela, AirSaas fluidifie la collaboration entre l'IT et les métiers. Les projets sont mieux préparés en amont. Vous restez agile tout au long du cycle de vie du projet pour maximiser l'engagement des collaborateurs et l'adoption du client final.</p>" }, { "title": "Communiquez mieux en interne", "body": "<p>La mise en place d'un plan de communication est bénéfique dans l'ensemble des entreprises et augmente la performance des DSI. Destiné aux membres du Comex et aux responsables métiers, il a l'avantage de diminuer la frustration, valoriser les équipes IT, et former l'ensemble des responsables aux méthodes qui fonctionnent. Une bonne communication de suivi d'avancée est d'autant plus importante avec un fonctionnement à distance. Le rapport flash automatique est votre meilleur allié !</p>" }] }, { "type": "intro", "title": "Les <strong>différentes typologies</strong> d'outils de pilotage de projet", "body": "<p>Il existe différents types de pilotage de projet, qui ne servent pas les mêmes objectifs. Pourtant, il n'est pas rare qu'il y ait des confusions, notamment entre ceux qui permettent le pilotage d'un projet, et ceux qui visent à simplifier la gestion d'un portefeuille de projets.</p>", "subSections": [{ "title": "Les outils de pilotage d'un projet unique : la gestion de projet", "body": "<p>Les outils de gestion de projet facilitent le pilotage des différents aspects d'un seul et même projet. Ils permettent d'accompagner le chef de projet ou le comité de pilotage sur un ensemble de tâches. Ils permettent de :</p><ul><li>Respecter les objectifs de chaque équipe</li><li>S'assurer de la tenue des délais d'exécution de chacun</li><li>Assurer un suivi global de l'avancée de toutes les équipes</li><li>Organiser la planification de toutes les étapes nécessaires au projet via un tableau de bord</li><li>Engager les collaborateurs travaillant sur le projet grâce à un espace collaboratif</li></ul>" }, { "title": "Les outils de pilotage de projets multiples : la gestion de portefeuilles de projets", "body": "<p>Ces outils vont permettre de faciliter la planification, non pas d'un, mais de tous les projets d'une entreprise.</p><p>Les petites entreprises qui n'ont que peu de projets n'ont pas forcément besoin d'outils permettant le pilotage de portefeuilles de projets. Mais à mesure qu'elles grandissent, les projets se multiplient, jusqu'à ce qu'une gestion globale et organisée de l'ensemble des projets prenne énormément de temps à chaque chef de projet ou au comité de pilotage : c'est le signe qu'il faut sûrement investir dans un tel outil.</p><p>Un outil de pilotage de portefeuilles de projets permet de :</p><ul><li>Hiérarchiser l'importance de chaque projet</li><li>Donner une visibilité totale sur la conduite de l'ensemble des projets</li><li>Permettre au chef de projet ou au comité de pilotage de connaître l'avancée de chaque projet</li><li>Préciser les missions que doivent accomplir chaque responsable de projet</li><li>Instaurer une méthodologie collaborative entre les équipes et les services de l'entreprise</li></ul>" }] }, { "type": "intro", "title": "<strong>La naissance récente</strong> des outils de pilotage de projet", "subSections": [{ "title": "Depuis combien de temps les outils de pilotage de projet sont-ils utilisés ?", "body": "<p>On voit qu'il existait déjà des outils de pilotage de projet sur le marché dès 1980, mais que de nouveaux outils semblables ont continué d'être développés entre-temps.</p><p>Un autre fait à relever : si, depuis quelques années, ces logiciels ont tendance à répondre aux besoins de gestion de projet unique mais aussi de portefeuilles projet, ça n'a pas toujours été le cas. Certains d'entre eux ont été initialement créés pour traiter seulement l'une de ces deux problématiques.</p>" }, { "title": "Quel a été le premier besoin à apparaître : le pilotage de projet unique ou la gestion de portefeuille de projets ?", "body": "<p>Comme on le constate sur le graphique, la plupart des outils de gestion de portefeuille de projets ont d'abord été créés dans l'optique de répondre au besoin de pilotage d'un projet unique. Ce n'est qu'au fil des années que ces derniers ont été complétés pour permettre de mener plusieurs projets de front de manière optimale.</p><p>Il faut tout de même relever que certains logiciels comme Planview avaient pris la décision de centrer leur solution sur la gestion des portefeuilles projets dès leur création, et que d'autres outils comme Sciforma ou Ganttic répondaient d'emblée aux deux problématiques : la gestion de projet unique, et de portefeuille de projets !</p><p>L'écrasante majorité des outils de pilotage de projet traite aujourd'hui ces deux problématiques dès leur création : il y a un besoin de simplifier la prise de décision entre les différents acteurs, que ce soit à l'échelle d'un projet unique, ou au niveau plus global du portefeuille de projets.</p><p>S'ils ont des similitudes dans les objectifs qu'ils visent, les outils de pilotage de projet peuvent avoir des fonctionnalités assez différentes. L'origine de ces différences est double : selon le besoin auquel l'outil a été conçu pour répondre en premier, mais aussi en fonction de la vision du pilotage de projet qu'ils promeuvent.</p>" }] }, { "type": "intro", "title": "Des <strong>visions hétérogènes</strong> de la gestion de projet selon les DSI et le style de chef de projet", "body": "<p>Plusieurs raisons font que les logiciels de pilotage de projets peuvent proposer des fonctionnalités variées : la manière dont ils ont été développé à l'origine a une influence, mais leurs fonctionnalités dépendent aussi de la vision de la gestion de projets qu'ils promeuvent. Mais pourquoi plusieurs visions de la gestion de projet coexistent-elles dans les DSI ?</p>", "subSections": [{ "title": "D'une gestion de projets axée sur la technique au focus business", "body": "<p>Si la DSI a durant de nombreuses années été plutôt réservée à un rôle technique, elle est de plus en plus amenée à aider son entreprise à atteindre ses objectifs business. Elle ne doit plus se contenter de s'assurer du bon fonctionnement du run, mais doit aussi se rapprocher des différents métiers de son organisation pour comprendre leurs difficultés et être en capacité de leur apporter des solutions adaptées.</p><p>Les besoins des DSI en matière d'outils de pilotage de projets ont donc beaucoup évolué. En effet, une DSI n'aura pas besoin des mêmes fonctionnalités selon si elle vise à suivre des projets centrés sur la technique et à gérer des incidents informatiques ou si elle souhaite structurer une démarche collaborative afin de comprendre finement les besoins que ressentent les métiers au quotidien.</p>" }, { "title": "La gestion de projets dans les DSI transformée par l'avènement du digital", "body": "<p>Avec l'essor du poids du digital pour les organisations, les DSI peuvent apporter de la valeur à leur entreprise de multiples manières. Par exemple, en automatisant des processus métiers, la DSI permet aux collaborateurs de son entreprise d'optimiser leur temps de travail et ainsi d'être plus compétitifs. Un autre aspect sur lequel la DSI peut accompagner son entreprise est l'amélioration de son business model : le digital offre de nouvelles opportunités qui peuvent apporter énormément d'un point de vue business.</p><p>L'importance qu'a pris le digital ces dernières années a donc eu pour conséquence de changer la nature des missions que se voit confier la DSI. Et ces nouvelles missions ne se mènent pas de la même manière, ce qui amène la DSI à avoir de nouvelles attentes en matière d'outil de pilotage de projet !</p>" }, { "title": "L'évolution du rôle de la DSI : d'une fonction centrée sur le contrôle à une nécessité de collaborer avec les métiers", "body": "<p>Les deux évolutions que l'on a décrites plus haut ont pour conséquence de transformer la manière dont la DSI doit collaborer avec les métiers de son entreprise. Si on prend l'exemple d'une DSI axée sur la technique, une de ses priorités va être de s'assurer du bon fonctionnement du run afin qu'aucun collaborateur n'ait à souffrir de problèmes purement techniques. Mais si la DSI a pour ambition d'apporter de la valeur à son entreprise d'un point de vue business, elle doit se donner les moyens d'échanger régulièrement avec les métiers afin de comprendre de quelle manière elle pourrait les aider à atteindre leurs objectifs business.</p><p>Une DSI qui vise à contrôler les comportements de ses collaborateurs pour éviter d'affecter négativement le SI n'aura pas du tout besoin du même type d'outil de pilotage projet que celle qui ambitionne d'instaurer un dialogue fort avec les métiers en vue de leur apporter de la valeur dans leur cœur de métier.</p>" }] }, { "type": "intro", "title": "Choisir son outil <strong>en fonction de sa vision</strong> du pilotage de projet", "body": "<p>On a vu que les outils de pilotage de projet n'offrent pas tous les mêmes fonctionnalités. La meilleure manière de trouver l'outil idéal à acquérir est donc de s'interroger sur sa vision du pilotage de projet : quels sont mes attentes et objectifs, et plus que ça, quelle est la place qui est attendue de la DSI dans mon entreprise ?</p>", "subSections": [{ "title": "Des outils de gestion de portefeuille projets diversifiés", "body": "<p>Tout d'abord, il faut noter que les outils de pilotage de portefeuille projet peuvent présenter de nombreuses fonctionnalités différentes qui permettent notamment de :</p><ul><li>Gérer et attribuer les ressources disponibles</li><li>Prioriser et hiérarchiser les projets</li><li>Engager et responsabiliser le chef de projet</li><li>Gérer les budgets engagés</li><li>Gérer les risques</li><li>Centraliser les informations clés</li><li>Évaluer la rentabilité de chaque projet</li><li>Communiquer dans un espace collaboratif structuré</li></ul><p>Mais plus que de dresser une liste des fonctionnalités que peuvent comporter ces logiciels, il est intéressant de remarquer que des différences de styles entre outils plus structurantes existent.</p>" }, { "title": "Les outils de gestion de projet : all-in-one VS spécialisés", "body": "<p>Tous les outils de pilotage projet n'ambitionnent pas de répondre au même nombre de besoins. Alors que certains (comme les logiciels de type ERP) aspirent à répondre à l'ensemble des besoins des DSI, d'autres outils préfèrent se spécialiser sur une ou plusieurs des fonctionnalités classiquement proposées par les outils de gestion de portefeuille de projets.</p><p>Chacun de ces deux types d'outils présente des avantages et des inconvénients. Un ERP complet permet de centraliser toutes les actions sur un même logiciel, mais présente l'inconvénient d'être complexe à faire évoluer : en effet, ces solutions sont peu flexibles et leur montée de version est lente et coûteuse.</p><p>A l'inverse, un outil de gestion de projet spécialisé présente l'inconvénient de ne pas proposer autant les fonctionnalités, mais offre d'autres avantages : il est plus rapide à implémenter, et permet de réduire le coût de change lorsque l'entreprise évolue.</p>" }, { "title": "Les outils de gestion de portefeuille projet centrés sur l'expérience utilisateur", "body": "<p>Certains outils de gestion de projet ont été développés avec l'objectif de proposer une interface particulièrement intuitive à leurs utilisateurs. Ce genre d'outil est idéal lorsque l'on souhaite structurer une démarche collaborative entre la DSI et des profils moins techniques. En effet, inviter des métiers à travailler sur les mêmes logiciels que ceux utilisés par les équipes IT peut les décourager et nuire fortement à leur implication.</p><p>Ainsi les outils ayant misé sur l'UX simplifient la collaboration entre des profils business et des profils techniques en proposant une interface compréhensible rapidement par toutes les parties prenantes, tout en maximisant le taux d'adoption général du logiciel.</p>" }, { "title": "Prendre compte les méthodologies intrinsèques de chaque outil", "body": "<p>Tout outil porte nécessairement une méthodologie plus ou moins poussée en lui. L'adéquation entre la méthodologie portée par un outil et celle déjà en place dans l'entreprise qui l'utilise est un facteur clé du taux d'adoption de ce logiciel par les collaborateurs.</p><p>En effet, il faut que la méthodologie intrinsèque de votre outil corresponde à vos processus de travail, à vos objectifs et à votre vision du pilotage de projet. Autrement, chacun de vos collaborateurs devra redoubler d'efforts pour prendre le logiciel en main et s'en servir, ce qui réduira forcément son taux d'adoption et donc, son impact dans l'entreprise.</p>" }, { "title": "L'outil de gestion de projet comme vecteur de changement de culture d'une entreprise", "body": "<p>S'il est préférable d'adapter son choix d'outil à la méthodologie déjà mise en place dans l'entreprise, il faut tout de même remarquer que l'on peut aussi se servir d'un outil de gestion de pilotage projet comme d'un levier pour impulser des changements dans les habitudes de travail existantes. En effet, la culture de l'entreprise est le fruit de son environnement - un environnement dont font partie les logiciels que vous utilisez !</p><p>Deux conditions sont primordiales pour maximiser l'impact de l'outil. D'abord, il faut accompagner la mise en place de l'outil par des directives et des consignes allant dans le même sens que le changement que l'on veut créer. Mais il faut aussi que la méthodologie portée par l'outil ne soit pas trop éloignée de celle qui existe actuellement dans votre entreprise, car transformer complètement les pratiques est compliqué et ne peut se faire que sur le temps long.</p><p>En conclusion: l'idéal est donc d'orienter votre choix vers un outil portant une méthodologie proche de celle qui est déjà en place dans votre entreprise, ou au moins de celle que vous aimeriez installer.</p>" }] }, { "type": "intro", "title": "<strong>Quel type d'outil de pilotage</strong> de projet est AirSaas ?", "body": "<p>AirSaas est un PPM plutôt léger qui ne vise pas à être un logiciel tout-en-un, mais qui comporte la plupart des fonctionnalités-clés dont une DSI a besoin pour assurer l'exécution de ses projets.</p>", "subSections": [{ "title": "Un outil de pilotage projet souple et intégrable facilement", "body": "<p><strong>Jira</strong><br/>En intégrant Jira à AirSaas, vous obtenez automatiquement les données d'avancement des projets dans la plateforme. Cela vous permet d'avoir une vue globale de l'ensemble des projets et de leurs états d'avancement sans efforts.</p><p><strong>Microsoft Teams</strong><br/>AirSaas est intégré à Microsoft Teams. Automatiquement, les informations les plus importantes sur les projets en cours sont envoyées sur vos canaux de communication Teams dédiés. Avec cette intégration, vous pouvez partager simplement l'avancée des projets avec l'ensemble de l'entreprise. Si vous utilisez d'autres solutions, n'hésitez pas à nous le dire !</p>" }, { "title": "Un outil de pilotage projet avec une méthodologie pensée pour impliquer les métiers", "body": "<p>Notre pari : pour parvenir à impliquer les métiers, la DSI doit leur proposer un outil qu'ils sauront prendre en main rapidement, sans friction. Nous pensons que ce n'est pas en forçant les métiers à travailler sur des outils complexes que les entreprises parviendront à briser les logiques de silos et à structurer une collaboration étroite métiers/DSI.</p><p>Nous avons poussé la logique collaborative jusqu'au bout : AirSaas propose un moteur de recherche de solutions (externes/internes) accessibles aux responsables métiers. Lorsqu'un métier a un besoin, il cherche déjà des solutions de son côté sans forcément prévenir la DSI qui peut même se retrouver face à du Shadow IT.</p><p>Notre idée ici est de donner les outils à la DSI pour encadrer ces pratiques et structurer leurs efforts de recherche de solution en leur faisant comprendre les contraintes techniques du SI.</p><p><strong>AirSaas</strong> est un PPM léger, qui s'intègre à l'existant, et qui porte une méthodologie collaborative forte afin d'impliquer les métiers.</p>" }] }, { "type": "cta", "title": "Découvrez comment AirSaas peut vous aider", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }] }, { "slug": "portfolio-management", "type": "solution", "meta": { "title": "La solution de portfolio management qui accélère la transformation de votre entreprise", "description": "La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les problèmes les plus fréquents en gestion de portefeuille de projets. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches." }, "sections": [{ "type": "hero", "title": "La solution de <strong>portfolio management</strong> qui accélère la transformation de votre entreprise", "body": "<p>La transformation de votre entreprise mérite un outil PPM qui vous aide à dépasser les problèmes les plus fréquents en gestion de portefeuille de projets. Grâce à AirSaas, accélérez votre prise de décision, gardez une transparence totale sur les priorités de vos projets, et dites adieu au micro-management de tâches.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "testimonials", "title": "Témoignages clients", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp" }] }, { "type": "stats", "title": "<strong>Les chiffres</strong> qui vous feront adopter AirSaas", "items": [{ "value": "80%", "label": "C'est la réduction moyenne du nombre de réunions projets constatée après 4 mois d'utilisation d'Airsaas. Pourquoi faire un meeting quand l'information est claire, centralisée et accessible à tous ?" }, { "value": "100%", "label": "C'est le taux de réduction du nombre de projet lancé sans capacité à faire ou sans objectif clair." }, { "value": "30K€", "label": "C'est le montant annuel moyen que vous dépensez en temps-homme pour faire du PowerPoint projet (si vous avez plus de 20 projets)." }] }, { "type": "intro", "title": "<strong>Une plateforme de gouvernance projet</strong> à la hauteur de vos ambitions", "body": "<p>Notre mission ? Vous permettre de devenir le pivot de la transformation de l'entreprise en structurant la gouvernance de tous les projets, grâce à une plateforme simple que le top management va adorer. La vôtre ? Faire passer votre entreprise à l'étape supérieure en gouvernance de projet !</p>" }, { "type": "feature-split", "title": "Partagez simplement les roadmaps <strong>à toute l'organisation</strong>", "body": "<p>Une roadmap, ça bouge, ça vit, c'est un élément clé pour aligner le top management en continu. Avec AirSaas, plus besoin de faire des PowerPoints à rallonge : l'information est centralisée, partageable et sympa à visualiser (parce que quand c'est beau, c'est quand même plus impactant).</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline" }, { "type": "feature-split", "title": "Un <strong>capacity planning par équipe</strong> simple et actionnable", "body": "<p>Visualisez en un clin d'oeil si vous êtes dans les clous... ou dans les choux. Grâce à cette vue vous avez les bases d'une discussion pragmatique pour prendre les décisions :</p><ul><li>Peut-on faire plus de projets ? Faut-il en enlever ?</li><li>Quels sont les jalons qui nous plombent ? Peut-on les découper ?</li><li>Doit-on recruter ou mettre l'équipe en tension ? Pendant combien de temps ?</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66334ee7bcfcb0aa45802537_Capacity%20screen.webp", "imageAlt": "Capacity Marketing" }, { "type": "feature-split", "title": "Chaque directeur définit <strong>ses prios</strong>", "body": "<p>Demandez aux directeurs de prioriser parmi les projets dont son équipe est à l'origine. Deux projets ne peuvent pas avoir la même priorité. Une fois prêts, ils valident leur choix. C'est simple, transparent et puissant.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07a346b12e77e37ddd72_Prioritization%20per%20team%20ppt%20d%26d.webp", "imageAlt": "Priorisation options" }, { "type": "feature-split", "title": "Diffusez un cadrage projet <strong>standardisé</strong>", "body": "<p>Remplissez les fiches cadrage de projet de manière collaborative, et guidez vos collaborateurs vers un véritable niveau d'excellence en gestion de projet. A vous une culture projet homogénéisée !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Presentation scope", "reversed": true }, { "type": "feature-split", "title": "Une <strong>newsletter sponsor</strong> que votre direction va adorer", "body": "<p>Un récapitulatif de la santé des projets vitaux de votre organisation pour leur permettre de \"sentir\" la tendance du moment.</p><p>Un aperçu de leurs projets, ceux en amélioration et ceux en dégradation qui nécessitent leur attention. En un clic, ils peuvent accéder à la fiche projet.</p><p>Un rappel des projets qui méritent d'être mis à jour. Si cette section est vide, vous êtes tranquile !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66543b6b307a64952dc9c936_Control%20tower%20email%20FR-1.png", "imageAlt": "Bilan de santé", "subSections": [{ "title": "Tendance des projets vitaux", "body": "Un récapitulatif de la santé des projets vitaux de votre organisation pour leur permettre de \"sentir\" la tendance du moment." }, { "title": "Tendance de leurs projets à eux", "body": "Un aperçu de leurs projets, ceux en amélioration et ceux en dégradation qui nécessitent leur attention. En un clic, ils peuvent accéder à la fiche projet." }, { "title": "Projets en retard d'actualisation", "body": "Un rappel des projets qui méritent d'être mis à jour. Si cette section est vide, vous êtes tranquile !" }] }, { "type": "feature-split", "title": "Votre reporting projet <strong>en un clic</strong>", "body": "<p>Générez votre <strong>reporting flash en un seul clic</strong>, et homogénéisez vos présentations, pour faciliter la prise de décision. Autant de temps gagné pour vous focaliser sur le coaching de vos chefs de projet et votre gouvernance.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report ppt" }, { "type": "feature-split", "title": "Fluidifiez votre prise de décisions <strong>importantes et urgentes</strong>", "body": "<p><strong>Centralisez vos décisions</strong> sous forme de Kanban, et partagez-les aisément avec toutes les parties prenantes de vos projets. Finies les informations perdues dans vos mails ou flux de discussions instantanées !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": true }, { "type": "intro", "title": "<strong>5 bonnes pratiques</strong> de portfolio management pour transformer votre entreprise plus efficacement", "body": "<p>Avoir un bon logiciel de gestion de portefeuille projet est crucial. Mais n'oubliez pas d'appliquer ces cinq bonnes pratiques à votre portfolio management au quotidien, pour en faire un véritable outil opérationnel et collaboratif, au service de votre transfo.</p>" }, { "type": "feature-split", "title": "Commencez par <strong>un cadrage de projet optimal</strong>", "body": "<p>Vous le savez mieux que quiconque : il est crucial de savoir qui fait quoi dans chaque projet. Qui est le sponsor ? Qui sont les key users ? Quel chef de projet prend quoi en charge ? Vous devez mettre en place les droits, devoirs et règles que chacun doit suivre, pour que le mode projet soit bien suivi par chacun.</p><p>Co-créez vos fiches de cadrage avec les chefs de projet sur AirSaas, pour les impliquer dès le départ, et diffuser une culture projet qui aligne chacune des parties prenantes de la transformation de l'entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d473f144eace1121240b18_Modal%20-%20create%20project.webp", "imageAlt": "Cadrage de projet dans votre logiciel PPM" }, { "type": "feature-split", "title": "Réduisez <strong>les durées</strong> de vos projets dans le portefeuille", "body": "<p>Votre challenge : faire en sorte qu'un projet ne dépasse jamais les trois mois. Voilà la clé pour dynamiser votre roadmap avec toutes vos parties prenantes, et vous aligner sur les besoins de l'entreprise, qui nécessite de plus en plus d'innovations et d'agilité.</p><p>Découpez en différentes phases vos \"gros\" projets, pour rendre votre processus de gestion de portfolio projet plus dynamique.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d73278ff90d9fe4f02eeb8_Portfolio%20project%20reminder%20late.webp", "imageAlt": "Reporting", "reversed": true }, { "type": "feature-split", "title": "Marketez avec <strong>impact</strong> vos programmes de transformation", "body": "<p>Bien communiquer les enjeux stratégiques liés à chacun de vos grands programmes est crucial pour motiver les différentes parties prenantes - et notamment les métiers et les équipes IT.</p><p>Donnez du sens à vos programmes dans la manière dont vous les formulez dans votre outil de portfolio management.</p>" }, { "type": "feature-split", "title": "Ritualisez vos <strong>reportings</strong>", "body": "<p>Votre reporting est l'élément-clé qui vous permet de prioriser, de fluidifier la prise de décision en Copil, mais aussi de motiver tous les acteurs de la transformation de votre entreprise au quotidien.</p><p>Gagnez du temps sur la création de vos reportings en utilisant un outil PPM qui automatise votre flash report, dans un format aisément compréhensible.</p><p>Puis envoyez ce reporting flash à toutes vos parties prenantes à intervalles réguliers, pour leur permettre de faire une revue de portefeuille projet claire, et de visualiser aisément les urgences et les risques en cours.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting", "reversed": true }, { "type": "feature-split", "title": "Placez <strong>la transparence au coeur de votre portfolio</strong> project management", "body": "<p>La transparence permet de générer de l'engagement de la part des différents acteurs de vos projets, et vous aide à les solliciter rapidement en cas d'urgence ou d'avancement à plat.</p><p>Facilitez l'accès de tout le monde aux différents jalons de vos projets et aux décisions qui sont prises, en centralisant tout sur une même plateforme qui permet d'avoir des vues personnalisables sur le portfolio de projets.</p><p>Sponsors, métiers, directions générales, chefs de projets : tout le monde a le même accès à la même information, pour être bien aligné autour des priorités et des besoins de chaque projet.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659c4b7b9b402047debe417c_portfolio4.svg", "imageAlt": "la transparence au coeur de votre portfolio" }, { "type": "cta", "title": "Et si vous repreniez <strong>le contrôle de votre portefeuille</strong> de projets ?", "body": "<p>Adoptez dès maintenant une solution de gestion de gouvernance moderne, qui fait gagner vos projets en temps et en efficacité.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "feature-split", "title": "<strong>Grâce à sa marketplace AirSaas</strong> s'intègre nativement à vos outils du quotidien", "body": "<p>Centralisez toutes vos informations cruciales (tickets, jalons…) depuis vos outils de gestion de tâches sur AirSaas, et diffusez-les via vos canaux de communication interne. Tout le monde est au diapason, et vous gouvernez de manière optimale.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d484f5bef7b761e48fea37_Automation%20-%20integrations.webp", "imageAlt": "Automation - integrations" }] }, { "slug": "revue-de-portefeuille", "type": "solution", "meta": { "title": "L'outil de revue de portefeuille projets moderne qui simplifie votre gouvernance", "description": "Parce que la revue de portefeuille est au cœur de votre process de transformation d'entreprise, AirSaas simplifie leur planification et leur préparation, en vous proposant des tableaux de bord consolidés et un reporting automatisé." }, "sections": [{ "type": "hero", "tag": "SOLUTION", "title": "L'outil de revue de portefeuille projets moderne qui simplifie votre gouvernance", "body": "<p>Parce que la revue de portefeuille est au cœur de votre process de transformation d'entreprise, AirSaas simplifie leur planification et leur préparation, en vous proposant des <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-portefeuille-de-projet\">tableaux de bord consolidés</a> et un reporting automatisé.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "Le tableau de bord préféré des DSI et PMO pour leurs revues de portefeuille", "body": "<p>Les portefeuilles de projets les plus larges ont besoin d'un <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\">outil PPM</a> simple à prendre en main, personnalisable et orienté valeur. Bonne nouvelle : c'est comme ça qu'a été conçu AirSaas !</p>", "subSections": [{ "title": "Une visualisation macro claire de votre portefeuille", "body": "Sortez de la simple revue projet par projet, pour visualiser globalement l'ensemble des projets, et rassembler les informations qui vous permettent de prendre les bonnes décisions." }, { "title": "Un flash report pour bien préparer vos revues", "body": "Gagnez du temps dans la préparation de votre revue de portefeuille, en consolidant toutes vos données-clés dans un format hyper lisible, qui se focalise sur les jalons des projets, leurs risques, et leurs priorités." }, { "title": "Une expérience utilisateur simplissime", "body": "Impliquez toutes vos parties prenantes grâce à une plateforme aisément paramétrable, intégrable à votre stack d'outils actuels, et alignez chacun autour de votre gouvernance projet." }] }, { "type": "feature-split", "title": "Vos données consolidées dans une seule plateforme", "body": "<p>Grâce à AirSaas, visualisez toutes les données dont vous avez besoin pour préparer vos revues de portefeuille, sans avoir besoin d'aller les chercher à droite et à gauche.<br/><br/>Tout se trouve là, dans votre tableau de bord de gouvernance projet, consolidé et mis à jour par vos différents chefs de projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Des vues personnalisables pour mieux classifier vos projets", "body": "<p>Sur AirSaas, visualisez vos projets en fonction de leur niveau de risque, de leur météo, ou encore de leur statut.<br/><br/>Une vue liste pour bien visualiser les indicateurs-clés des projets, une vue Kanban pour vous focaliser sur leur état d'avancement, et une vue timeline pour observer le tout sous forme de diagramme de Gantt. De quoi préparer votre revue de portefeuille en quelques clics.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Votre reporting flash automatisé", "body": "<p>Parce que le <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">reporting</a> est un moment-phare de toute gestion de portefeuille de projets, automatisez-le grâce à AirSaas, pour vous focaliser sur le pilotage de vos programmes de transformation.<br/><br/>Vous gagnez ainsi du temps dans la préparation de votre revue de portefeuille, en consolidant toutes les données-clés dans un format hyper lisible, qui se focalise sur les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">jalons d'avancement des projets</a>, la météo, les risques, et les priorités.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Optimisation des ressources disponibles", "reversed": false }, { "type": "feature-split", "title": "Une expérience utilisateur moderne et fluide", "body": "<p>Les PMO et DSI qui nous ont aidé à concevoir AirSaas nous l'ont dit : bon nombre d'outils de gestion de portefeuille projets sont trop complexes, trop peu lisibles et personnalisables.<br/><br/>C'est pour répondre à ce souci qu'AirSaas est pensé pour simplifier sa prise en main et son utilisation au quotidien. Alignez chacune des parties prenantes de votre transformation d'entreprise sur la plateforme, et laissez le collaboratif vous aider à mener plus loin vos projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "cta", "title": "Choisissez de gagner du temps et du contrôle", "body": "<p>Adoptez dès maintenant une solution efficace de flash report projet</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "intro", "title": "Fluidifiez votre gouvernance projet grâce à votre outil PPM nouvelle génération", "body": "<p>Plus qu'un simple outil de revue de portefeuille, AirSaas est une véritable solution de gestion de portfolio de projets, qui vous accompagne dans chacune de vos missions, depuis la planification stratégique au Copil</p>" }, { "type": "feature-split", "title": "Collaborez lors de la création de vos fiches de cadrage de projet", "body": "<p>Rassemblez vos chefs de projet et métiers dans votre logiciel de gestion de portfolio, pour co-créer avec eux les fiches de cadrage de vos projets. Homogénéisez et standardisez la culture projet de votre entreprise, et faites en sorte que chaque projet parte toujours sur le bon pied.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Générez vos bilans de projets en quelques clics", "body": "<p>Un projet est finalisé ? Il est temps d'en faire le bilan auprès de vos différentes parties prenantes grâce à AirSaas. Visualisez aisément vos délais, l'engagement de vos équipes, vos budgets et coûts ainsi que les retours DAKI de chacun. De quoi motiver tout le monde, et les féliciter des beaux efforts accomplis.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Synchronisez vos outils préférés grâce à nos intégrations natives", "body": "<p>Fini le temps passé à reporter à la main des informations d'une plateforme à une autre ! Sur la marketplace AirSaas, retrouvez des intégrations à vos outils de gestion de tâches préférés (Jira, Asana, ClickUp, Monday), à vos outils de communication (Microsoft Teams), ou à votre logiciel de service client (Zendesk).</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "intro", "title": "6 clés pour rendre vos revues de portefeuille de projet plus efficaces", "body": "<p>Préparation, priorisation et arbitrage : voici les trois maîtres-mots d'une bonne revue de portefeuille projets. Prenez le temps d'appliquer les six bonnes pratiques suivantes à votre prochaine réunion, et observez-en les effets en termes d'efficacité.</p>" }, { "type": "feature-split", "title": "Prioriser les sujets à aborder", "body": "<p>Appliquez une priorisation des sujets à aborder lors de votre revue en fonction de leur alignement par rapport aux objectifs stratégiques et organisationnels. L'idée ? Faire en sorte d'aborder les sujets les plus importants en premier - soit ceux qui apportent le plus de valeur à l'organisation, et qui sont les plus à risques au moment de la revue de portefeuille. Privilégiez le fait de retarder ou rejeter un projet à faible valeur ajoutée pour l'entreprise, plutôt qu'un projet-phare qui permet de lui donner un nouvel avantage concurrentiel ou une nouvelle innovation.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d7381a68b84adf7cb36003_Portfolio%20projects%20kanban%20status.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Inviter les bonnes personnes à votre revue de portefeuille", "body": "<p>Invitez à vos revues de portefeuille de projets uniquement les personnes qui peuvent prendre des décisions et qui permettent d'éclairer le processus décisionnel. Vous pouvez ainsi focaliser l'attention sur le fait de faire avancer votre portfolio project management, et de resserrer les débats autour de l'essentiel. L'idéal ? Inviter le Codir, les sponsors des différents programmes (les directions), et éventuellement les gestionnaires des projets des projets à risques sur le moment.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "feature-split", "title": "Envoyer votre reporting en amont", "body": "<p>L'envoi en amont de votre flash report permet de fluidifier la <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-decider-en-copil\">prise de décision</a> en revue de portefeuille, en alignant toutes les parties prenantes autour des mêmes informations. Vous pouvez alors piloter la réunion de manière plus efficace, plus fluide.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Adopter une structure claire pour votre revue de portfolio", "body": "<p>Mettez toujours en place la même structure de présentation, et un ordre du jour bien structuré : état d'avancement des projets, achèvement des projets finalisés, décisions à venir, gestion des ressources nécessaire, et informations sur les nouveaux projets à venir. Votre flash report multi-projets doit lui-même toujours adopter le même format pour être vraiment efficace.</p>", "reversed": true }, { "type": "feature-split", "title": "Ritualiser votre revue de portefeuille", "body": "<p>Organisez vos revues à échéances fixes, en fonction des besoins de votre organisation. La plupart des PMO et DSI font une revue de portefeuille de projets mensuelle. Organisez également cette revue après les autres types de réunions liées à votre gouvernance de portfolio de projets (après vos réunions d'avancement hebdomadaires avec les chefs de projets, et après votre réunion de coordination des ressources bi-mensuelle avec les chefs d'équipes). Ainsi, vous êtes sûr d'avoir toutes les informations nécessaires à la revue de portefeuille, et de présenter des métriques-clés bien à jour en temps réel.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66865ccd6319bebdceb619e4_Presentation-review-slide.png", "imageAlt": "Pilotage de projet", "reversed": false }, { "type": "feature-split", "title": "Aller au-delà des chiffres", "body": "<p>Ne vous focalisez pas uniquement sur les métriques-clés liées à vos projets. Les chiffres parlent autant que les retours des équipes elles-mêmes - y compris du chef de projet en charge d'un projet spécifique. Dédiez toujours un temps de parole aux différents responsables, ou incluez à vos présentations des verbatims pour mobiliser l'attention des différents décideurs pendant la revue de portefeuille.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/659ed24faa749ab95880701a_portfolio8.svg", "imageAlt": "Reporting projet", "reversed": true }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)" }] }, { "type": "cta", "title": "Simplifiez vos revues de portefeuille dès maintenant", "body": "<p>Choisissez une solution PPM collaborative et moderne, qui fluidifie vos prises de décisions et booste votre reporting.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }, { "slug": "tableau-de-bord-dsi", "type": "solution", "meta": { "title": "Le tableau de bord que tous les DSI attendaient | AirSaas", "description": "AirSaas, le tableau de bord DSI nouvelle génération. Pilotez vos projets, ressources et budgets avec des indicateurs intelligents d'aide à la décision." }, "sections": [{ "type": "hero", "title": "Le tableau de bord que tous les DSI attendaient", "body": "<p>Le vieil adage disant \"on ne peut pas améliorer ce que l'on ne mesure pas\" s'applique particulièrement à la Direction des Systèmes d'Information. Avant même d'\"améliorer\", \"mesurer\" permet d'éviter les glissements rapides, propres aux métiers de l'IT, ayant des forts impacts sur le client, interne ou externe (retards, surcoûts, etc.).<br/>La mesure et le suivi des indicateurs clés permettent ensuite les améliorations, les optimisations, la mise en place de stratégies de pilotage ambitieuses avec la Direction Générale.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }, { "type": "intro", "title": "AirSaas, le tableau de bord DSI nouvelle génération", "body": "<p>Dans un contexte où la transformation des entreprises s'accélère, où l'innovation n'est plus cantonnée à un département mais un impératif à la compétitivité de l'entreprise, les <a href=\"https://www.airsaas.io/fr/solution/outils-de-pilotage-projet\">projets digitaux</a> se multiplient et mettent la direction des systèmes d'information au centre de toutes les attentions. Nous avons créé le tableau de bord idéal pour vous permettre de satisfaire les attentes de la Direction Générale et devenir le premier business partner des métiers.</p>" }, { "type": "feature-split", "title": "Le pilotage par la valeur", "body": "<p>La clé de la réussite pour l'entreprise est de <strong>prioriser les investissements</strong> qui lui apporteront le plus de valeur. Le rôle du DSI est de mettre en place la <strong>gouvernance</strong> et les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">indicateurs</a> permettant de prendre les bonnes décisions afin d'optimiser le pilotage des projets à mener.</p><p>Pour cela, il faut pouvoir rassembler les membres de direction autour d'un tableau de bord DSI présentant les données essentielles des différentes activités afin d'être <strong>efficace dans la prise de décision</strong>.</p><p>Les indicateurs principaux se rassemblent en 3 domaines :</p><ul><li>Domaine de la planification et de l'avancée des projets</li><li>Domaine du pilotage des ressources</li><li>Domaine du suivi des budgets</li></ul>", "subSections": [{ "title": "Pour la planification, AirSaas propose trois vues ayant chacune une utilité différente", "body": "La vue liste permet, pour un état d'avancement donné, de <a href=\"https://www.airsaas.io/fr/solution/tableau-de-bord-gestion-de-projet\">passer en revue les projets</a> avec tous les indicateurs au premier plan. Quelles sont les actions à prendre pour faire passer ces projets à l'état suivant ?" }], "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Des vues différentes pour mieux piloter les projets" }, { "type": "feature-split", "reversed": true, "title": "Embarquez par une bonne communication", "body": "<p>Un projet réussi, c'est un projet livré dans les temps, au bon prix, mais aussi un projet qui a une adhésion forte de la part du client. Pour cela, il faut arriver à l'impliquer dans le cadrage et sur toute la durée du build du projet. Une bonne communication est également indispensable pour garder la confiance de votre Direction Générale. Il faut arriver, à fréquence régulière, à dresser le tableau de l'avancée des projets, l'évolution des indicateurs clés, le suivi de la performance et sonder l'adhésion des équipes. Car l'humain reste le facteur numéro un du succès (ou de l'échec) de vos projets.</p><p>Pour cela nous mettons deux outils à votre disposition.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "title": "Le rapport flash automatisé", "body": "<p>Le <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">reporting</a> est essentiel. Il est malgré tout chronophage et souvent délaissé. Nous vous donnons la possibilité de générer des <a href=\"https://www.airsaas.io/fr/solution/flash-report-projet\">rapports flash</a> en un clic. Exportables en PDF ou en PowerPoint, vous pouvez ainsi tenir au courant les parties prenantes de l'avancée de vos activités.<br/>Le rapport flash rassemble les projets sur lesquels vous souhaitez communiquer. Pour chacun d'entre eux, deux slides sont générées : une slide de rappel des informations de cadrage, et une contenant les éléments clés de l'exécution.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash" }, { "type": "feature-split", "reversed": true, "title": "Suivi de l'indicateur d'adhésion", "body": "<p>Nous mettons à disposition un outil de sondage anonyme de confiance des parties prenantes dans l'adhésion du projet en cours. Plus ce degré de confiance est élevé, plus votre projet aura de chance d'être un succès. Au contraire s'il est faible, il faut agir vite. Rien de pire qu'un projet terminé mais ne correspondant pas au besoin du client.<br/>En un clic, envoyez le sondage à toutes les personnes intervenant sur le projet. Faites-le à intervalle régulier et évitez les mauvaises surprises dans le pilotage de vos projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd67b20f0e6f_dashboard.svg", "imageAlt": "Sondage collaborateur" }, { "type": "feature-split", "title": "Devenez un centre de profit plutôt qu'un centre de coût", "body": "<p>Historiquement, la DSI a toujours été vue comme un centre de coûts. Anciennement sous la responsabilité de la Direction des Finances, la DSI est maintenant de plus en plus valorisée et a sa place aux comités de direction des entreprises.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Transformer la DSI" }, { "type": "intro", "title": "Toutes les directions avaient leurs tableaux de bord - maintenant, vous aussi", "body": "<p>Vous n'avez pas attendu AirSaas pour vous constituer votre propre tableau de bord de la DSI, et vous avez raison. A la suite d'audits de plusieurs dizaines de DSI, nous avons développé un tableau de bord de pilotage pour les DSI.</p>" }, { "type": "feature-split", "title": "Des données consolidées", "body": "<p>Souvent mise en place sur Excel ou sur des outils de visualisation, les tableaux de bord que nous avons pu observer ne disposent pas d'une donnée consolidée. AirSaas se connecte aux différents outils de gestion de projet et vous propose une abstraction. La donnée est consolidée autours des projets, des solutions partenaires, des équipes impliquées, etc. pour vous permettre d'afficher et de suivre les indicateurs indispensables au pilotage de votre activité.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd35ed0f0e71_1.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Des indicateurs intelligents d'aide à la décision", "body": "<p>L'objectif ici est d'apporter des éléments d'attention aux DSI afin de leur simplifier la prise de décision. Par exemple, lorsqu'un projet nécessite une prise de décision depuis plusieurs semaines alors qu'il est stratégique pour une direction métier, il est important d'en être informé pour optimiser le pilotage de la performance de sa DSI.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd17cf0f0e87_2.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "title": "Simple et collaboratif by design", "body": "<p>Il est essentiel d'impliquer les équipes dans cette démarche. Pour cela il faut un outil simple, ne nécessitant pas de formation et permettant de travailler ensemble en fonction des droits d'accès de chacun. AirSaas a été conçu comme point de rencontre entre la DSI et les directions métiers.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fdde5c0f0e46_outil4.svg", "imageAlt": "Pilotage de projet" }, { "type": "intro", "title": "Pourquoi utiliser un tableau de bord est essentiel pour le pilotage d'un système d'information ?", "body": "<p>Si les DSI étaient auparavant centrées principalement sur des problématiques techniques, elles deviennent de plus en plus orientées business : le pilotage du système d'information est maintenant considéré dans une entreprise comme un levier important de création de valeur.</p><p>Mais si elle souhaite être en capacité d'aider son entreprise à atteindre ses objectifs business, le pilotage de la DSI doit être optimal. Et c'est là qu'un tableau de bord prospectif devient indispensable à la bonne gouvernance du système d'information.</p><p>En effet, si une organisation veut évoluer, elle doit forcément se donner les moyens de s'évaluer. Sinon, comment savoir si elle progresse et atteint ses objectifs ? Ainsi le tableau de bord prospectif est l'outil qui permet à la DSI de s'assurer un pilotage efficace au travers d'objectifs à court, moyen et long terme. Le but du tableau de bord prospectif est d'assurer que les buts seront atteints sans être entravés par une problématique d'ordre opérationnelle, ou organisationnelle.</p><p>Pour synthétiser, un tableau de bord de la DSI permet de :</p><ul><li>Assurer le pilotage optimal de la DSI</li><li>Instaurer une communication interne efficace</li><li>Repérer les tendances au sein de l'entreprise</li><li>Assurer la gestion du suivi dans le temps de chaque objectif</li><li>Analyser les écarts entre les objectifs fixés et ceux atteints</li><li>Responsabiliser chacun des collaborateurs en leur assignant la gestion d'objectifs</li></ul>" }, { "type": "feature-split", "reversed": true, "title": "La transposition infortune des systèmes traditionnels de gestion aux tableaux de bord des DSI", "body": "<p>Comme l'expliquent Philippe Rosé et Christophe Legrenzi dans leur ouvrage \"Les tableaux de bord de la DSI\", les systèmes d'information ont pendant longtemps été évalués grâce à des tableaux de bord et des indicateurs qui n'étaient pas adaptés à l'analyse du pilotage d'une DSI.</p><p>En effet, ce sont les indicateurs de performance issus du monde industriel qui ont été transposés dans les tableaux de bord afin d'analyser l'activité des DSI. Cependant, ces indicateurs traditionnels de pilotage (comprenant la comptabilité ou encore le contrôle budgétaire) ne sont pas du tout adaptés à l'élaboration d'un tableau de bord de la maintenance du système d'information qui assure le suivi d'activités qui, par nature, sont transverses.</p><ul><li>Les aspects technologiques et financiers des DSI étaient correctement évalués par ces indicateurs de performance dans les tableaux de bords, mais ils se révélaient incapables de traiter les informations relatives à la communication, aux collaborateurs ou encore à au pilotage de la stratégie de l'entreprise.</li><li>Les informations traitées par ces indicateurs concernent le passé et le présent, mais très rarement le futur. Ces tableaux de bords sont donc bien plus proches d'un simple rapport d'activités que d'un véritable outil de pilotage de la performance !</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd06800f0e86_3.svg", "imageAlt": "La transposition infortune des systèmes traditionnels de gestion aux tableaux de bord des DSI" }, { "type": "feature-split", "title": "D'un tableau de bord centre de coûts à un tableau de bord centre de profit", "body": "<p>Cette manière d'évaluer les performances de la DSI a forcément amené les entreprises à analyser les systèmes d'information en fonction de ce qu'ils coûtent. Conséquence : le pilotage des systèmes d'information via les tableaux de bord se fait principalement par les coûts et non par la valeur qu'ils peuvent apporter.</p><p>A titre d'exemple : il a été constaté qu'une large majorité des tableaux de bord des DSI incorporent une notion de budget, alors que seulement 20% d'entre elles ont mis en place des indicateurs afin d'évaluer la valeur produite par la DSI ! Dès lors, on comprend que les SI soient majoritairement perçus comme des centres de coûts et non de valeur.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd4d920f0e88_7105959688182da7475c8681c14e857d_4.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Le tableau de bord de la DSI au service de la direction générale", "body": "<p>Les tableaux de bord de la DSI sont indispensables à la direction générale si cette dernière veut piloter correctement la transformation digitale de l'entreprise : en effet, les indicateurs du tableau de bord de la direction sont essentiels pour rendre compte du pilotage de la DSI et donner des informations permettant une gouvernance optimale des ressources humaines et budgétaires de l'entreprise.</p><p>Parmi les usages principaux du tableau de bord de la direction :</p><ul><li>Quel est le coût total de l'informatique dans l'entreprise ?</li><li>Les ressources sont-elles engagées sur les projets apportant le plus de valeur ?</li><li>A quel point l'informatique apporte de la valeur aux différents métiers et à la performance globale de l'entreprise ?</li><li>Où se situe la performance des SI par rapport à la concurrence ?</li><li>Quels sont les futurs projets sur lesquels investir ?</li></ul><p>Les Directions Générales doivent donc inciter les DSI à créer des indicateurs de tableau de bord prospectif permettant de mesurer leur performance en fonction de la valeur créée par rapport aux intérêts stratégiques de l'entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "title": "Des principes à respecter dans la construction des indicateurs d'un tableau de bord", "body": "<p>Suivre quelques principes formels lors de la construction des indicateurs des tableaux de bord est essentiel pour contrôler le pilotage de la DSI :</p><ul><li>Tous les indicateurs du tableau de bord informatique de la Direction des Systèmes d'Informations doivent être nommés</li><li>Tous les indicateurs du tableau de bord informatique de la DSI doivent être définis et la définition doit être connu par tous</li><li>Chaque indicateur du tableau de bord informatique de la Direction des Systèmes d'Informations doit être assorti d'un objectif : sans, il devient inutile</li><li>Les indicateurs du tableau de bord informatique de la Direction doivent prendre en compte, le passé, le présent mais aussi le futur</li><li>Pensez à construire des indicateurs de tableau de bord évaluant des résultats (statiques) mais aussi des processus (dynamiques)</li><li>Construisez vos indicateurs de tableau de bord des études de vos activités afin qu'ils puissent être comparables entre eux</li><li>Indiquez la fréquence de mise à jour de l'indicateur de tableau de bord (annuelle / trimestrielle / mensuelle / journalière…)</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Pilotage de projet" }, { "type": "feature-split", "reversed": true, "title": "Penser les indicateurs de tableau de bord comme le reflet des objectifs de l'entreprise", "body": "<p>Bien qu'on puisse trouver des tableaux de bords avec des indicateurs de performance déjà pensés et prévus pour pouvoir s'appliquer à toute entreprise, la solution optimale est d'opter pour la personnalisation.</p><p>Chaque tableau de bord servant au pilotage d'une DSI doit être construit au regard des objectifs de l'entreprise : ces derniers doivent refléter ses ambitions stratégiques.</p><p>Chaque organisation possède un fonctionnement spécifique, un tableau de bord informatique générique aura donc une efficacité limitée. Ainsi, les tableaux de bord les plus efficaces sont ceux qui décrivent le pilotage des systèmes d'information au regard du contexte de leur entreprise.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Penser les indicateurs de tableau de bord comme le reflet des objectifs de l'entreprise" }, { "type": "feature-split", "title": "Impliquer les métiers dans la fabrication des indicateurs du tableau de bord informatique", "body": "<p>Très souvent, les métiers sont très peu (voire pas du tout) impliqués dans la construction des indicateurs de performance et des tableaux de bord de la DSI. C'est une preuve supplémentaire qui témoigne que la majorité des tableaux de bord des DSI sont créés dans une logique centrée sur l'informatique, alors même que les bénéficiaires directs des solutions apportées seront bel et bien les métiers.</p><p>Impliquer les métiers dans l'élaboration des tableaux de bord est indispensable pour faire coller les indicateurs à la situation réelle de l'entreprise. L'idéal est de former des équipes constituées de responsables métiers (si possible volontaires) et accompagnées par des membres des équipes de la DSI.</p><p><strong>Pour résumer,</strong> construisez vos indicateurs de tableaux de bord :</p><ul><li>en respectant des principes de forme, afin qu'ils soient réellement exploitables</li><li>en les adaptant aux objectifs spécifiques de votre entreprise</li><li>en impliquant les directions métiers dans leur élaboration</li></ul><p>Si vous suivez ces principes, vous aurez de bonnes chances d'aboutir à un tableau de bord permettant réellement de piloter votre DSI de manière optimale.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Pilotage de projet" }, { "type": "cta", "title": "Découvrez comment AirSaas peut vous aider", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" } }] }, { "slug": "tableau-de-bord-gestion-de-projet", "type": "solution", "meta": { "title": "Le tableau de bord de gestion de projet moderne | AirSaas", "description": "AirSaas, le tableau de bord de gestion de projet conçu pour les DSI. Pilotez vos projets IT avec des indicateurs clés, des vues portfolio et des rapports flash automatisés." }, "sections": [{ "type": "hero", "title": "Le tableau de bord de gestion de projet moderne", "body": "<p>Comme tout organe de direction, la DSI a un besoin constant de mesurer son activité : c'est seulement de cette manière qu'elle est à même d'optimiser chacun de ses processus de gestion de projet et de réduire le nombre de dérapages avec des conséquences négatives fortes pour le client (dépassement des coûts, des délais de livraisons des projets…). Pour vous aider, nous avons conçu <a href=\"/gestion-de-projet/le-grand-guide-de-la-conduite-de-projet\">le grand guide de la conduite de projet.</a><br/><br/>Mesurer ses performances grâce à des indicateurs permet ainsi de calibrer les changements à implémenter afin d'augmenter la productivité de ses services et de pouvoir exécuter des projets encore plus ambitieux. La mesure et le suivi des indicateurs clés permettent ensuite les améliorations, les optimisations, la mise en place de stratégies de pilotage ambitieuses avec la direction générale.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "AirSaas, le tableau de bord de gestion de projet conçu pour les DSI", "body": "<p>L'importance de l'innovation ne cesse de s'accroitre pour les entreprises : les <a href=\"https://www.airsaas.io/fr/gestion-de-projet/pilotage-de-projet\">projets digitaux</a> se multiplient et leurs réussites deviennent une condition sine qua none à la compétitivité de l'organisation. En conséquence, les entreprises ont de plus en plus d'attentes envers les DSI, qui se retrouvent souvent au coeur des nouvelles stratégies mises en place. Notre tableau de bord gestion de projet a été créé afin de permettre à la DSI d'être en capacité de répondre aux besoins de son entreprise et de collaborer étroitement avec les métiers.</p>" }, { "type": "feature-split", "title": "Piloter par la valeur", "body": "<p>Une des clés pour assurer la pérennité de son entreprise est de savoir hiérarchiser les projets afin de prioriser ceux qui crééront le plus de valeur. Si elle veut être performante, la DSI doit créer des <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">indicateurs</a> qui permettront à la direction de prendre les meilleures décisions et d'assurer un pilotage optimal des projets IT. Pour cela il faut être en capacité d'informer efficacement les membres du board. L'<a href=\"https://www.airsaas.io/fr/solution/outils-de-pilotage-projet\">outil idéal</a> pour cela est un tableau de bord gestion de projet possédant des indicateurs offrant une visibilité sur trois des domaines principaux :</p><ul><li>La planification et le suivi de chaque projet</li><li>Le suivi des ressources disponibles</li><li>La gestion des budgets</li></ul>", "subSections": [{ "title": "AirSaas propose 3 vues pour offrir une visibilité totale sur vos projets :", "body": "Un suivi de l'avancée de chacun de vos projets, avec les indicateurs les plus importants. Ainsi vous savez constamment quelle est la prochaine étape pour faire évoluer vos projets." }, { "title": "Vue Kanban", "body": "Une vue Kanban qui aide à repérer des tendances générales parmi vos projets afin d'optimiser votre stratégie de pilotage." }, { "title": "Vue Timeline", "body": "Une vue timeline pour organiser l'exécution de tous vos projets sur le temps long. Elle permet de repérer en amont les surcharges de travail et d'anticiper les retards." }], "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "Portfolio projects list" }, { "type": "feature-split", "title": "Impliquez toutes les parties prenantes", "body": "<p>L'objectif suprême est de parvenir à livrer un projet qui satisfait parfaitement votre client tout en respectant les délais prévus. Un des facteurs principaux pour y parvenir est d'impliquer votre client dès la phase du cadrage, et tout au long de l'exécution du projet.<br/><br/>De même, vous devez aussi être constamment en capacité d'informer votre direction de l'avancée ainsi que de l'état de tous vos projets, afin de lui permettre de <a href=\"/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">piloter au mieux l'entreprise</a>.<br/><br/>Nous avons créé deux outils pour vous aider à atteindre ces objectifs.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Impliquez toutes les parties prenantes", "reversed": true }, { "type": "feature-split", "title": "Le rapport flash automatisé", "body": "<p>Si le reporting est indispensable au bon déroulement d'un projet, il reste trop souvent délaissé, notamment parce qu'il requiert énormément de temps. C'est pourquoi nous vous offrons la possibilité de générer automatiquement des rapports flash. Exportables au format PDF ou PowerPoint, ils vous permettent de communiquer sur vos avancées à l'ensemble des parties impliquées dans vos projets.<br/><br/><a href=\"/fr/solution/rapport-flash\">Le rapport flash</a> est composé de deux slides : l'une rappelle toutes les informations de cadrage, tandis que l'autre comporte toutes les informations nécessaires à la bonne exécution du projet.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Rapport flash automatique" }, { "type": "feature-split", "title": "Sondez vos collaborateurs grâce à l'indicateur d'adhésion", "body": "<p>Les chances de succès d'un projet augmentent lorsque ses parties prenantes ont confiance dans son exécution. Nous avons créé un outil de sondage anonyme afin que vous puissiez connaître le degré de confiance de chacune des parties dans vos projets. Ainsi, vous aurez les capacités de réagir à temps afin d'éviter de livrer un produit trop éloigné des attentes de votre client.<br/><br/>Vous pouvez envoyez ce sondage à toutes les personnes impliquées sur votre projet en moins d'une minute. Sonder régulièrement leur degré de confiance vous permettra d'assurer un résultat à la hauteur des espérances de chacun.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd67b20f0e6f_dashboard.svg", "imageAlt": "Sondage collaborateurs", "reversed": true }, { "type": "feature-split", "title": "Tableau de bord de gestion de projets : pourquoi est-ce crucial pour une direction des systèmes d'information ?", "body": "<p>A mesure que le digital se développe, les DSI sont de plus en plus amenées à se voir confier des missions touchant au coeur du business de leur entreprise : le système d'information est aujourd'hui considéré comme un des facteurs clés de la création de valeur.<br/><br/>Si une DSI souhaite accompagner le développement de son entreprise, elle doit diriger l'exécution de ses projets de manière optimale. Et justement, le tableau de bord de gestion de projet se révèle très vite être indispensable à un pilotage efficient d'une DSI.<br/><br/>Si l'on désire améliorer ses process, il faut d'abord être capable d'évaluer ses pratiques actuelles : c'est la meilleure manière pour savoir si les méthodes mises en place sont efficaces et permettent d'atteindre les objectifs fixés. Un <a href=\"/fr/solution/tableau-de-bord-dsi\">tableau de bord</a> projet permet donc d'assurer le pilotage des aspects opérationnels des projets IT, à court comme à long terme, mais aussi :</p><ul><li>à assurer l'exécution optimale de chaque projet</li><li>à structurer une communication interne performante</li><li>à analyser les tendances grâce à une visibilité sur l'ensemble des projets</li><li>à suivre les avancées de chaque projet au regard des objectifs fixés</li><li>à impliquer les collaborateurs en leur affectant à chacun des objectifs</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd66030f0e89_5.svg", "imageAlt": "Tableau de bord de gestion de projet" }, { "type": "feature-split", "title": "Quelques principes à respecter pour une gestion de portefeuille optimale", "body": "<p>Il est important de respecter certaines règles de forme lors de l'élaboration des indicateurs, afin de s'assurer qu'ils soient pertinents :</p><ul><li>Il est indispensable de nommer chacun des indicateurs</li><li>Il faut aussi définir chaque indicateur, et s'assurer que chaque collaborateur utilise la même définition</li><li>Il faut assortir chaque indicateur d'un objectif, si possible chiffré : à défaut, ils perdent presque tout intérêt</li><li>Les indicateurs doivent analyser le passé, le présent, mais aussi les évènements à venir : ils ne servent pas seulement à rapporter, mais bien à piloter</li><li>Les indicateurs construits autours de processus (dynamiques) sont tout aussi importants que ceux qui évaluent des résultats (statiques) : ne vous cantonnez pas à l'un de ces deux types</li><li>Pensez vos indicateurs de sorte qu'ils puissent être comparés entre eux lorsque c'est possible.</li><li>Rappeler la fréquence à laquelle votre indicateur devra être mis à jour (semestrielle/mensuelle/hebdomadaire).</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66867e827c10da64f5ea6d52_Graphic%20IT.svg", "imageAlt": "gestion de portefeuille optimale" }, { "type": "feature-split", "title": "Construisez les indicateurs de tableau de bord projet en fonction des ambitions de votre organisation", "body": "<p>Il existe des tableaux de bord dont le choix des indicateurs pertinents est déjà pensé, et qui ont pour vocation d'être capable de s'adapter à toutes, ou au moins, à un grand nombre d'entreprises. Cependant, prendre le temps d'élaborer des indicateurs personnalisés à son organisation reste la meilleure solution.<br/><br/>Chaque entreprise a des objectifs différents, et des caractéristiques qui lui sont propres : aussi, utiliser un template de tableau de bord universel ne peut avoir qu'une efficacité réduite. A l'inverse, un tableau de bord de gestion de projet dont les indicateurs ont été pensés en fonction des ambitions d'une entreprise sera forcément plus performant pour accompagner le pilotage d'une DSI.<br/><br/>Mais construire des critères en prenant en compte le contexte de l'entreprise (ses collaborateurs, les projets menés, les résultats que l'on souhaite atteindre) prend beaucoup de temps et est complexe. En effet, il faut une connaissance poussée de chacune des activités de l'organisation. Ainsi, il est fortement conseillé d'engager les directions métiers dans l'élaboration du tableau de bord et de ses indicateurs.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd0e210f0e8a_7.svg", "imageAlt": "Vos indicateurs de tableau de bord projet", "reversed": true }, { "type": "feature-split", "title": "Engager les métiers dans la fabrication des indicateurs du tableau de bord", "body": "<p>Il n'est pas rare que les directions métiers ne soient que très peu sollicitées dans l'élaboration des tableaux de bord des DSI. Pourtant, ce sont bien les métiers qui sont les destinataires et les utilisateurs de la grande majorité des solutions sur lesquelles travaillent les équipes IT !<br/><br/>Engager les directions métiers dans la construction et la mise en œuvre des indicateurs de vos tableaux de bord vous permet de juger de l'avancée de vos projets selon les critères qui importent au client final. C'est donc la meilleure manière de contrôler que le produit livré offre une pleine satisfaction à ses utilisateurs.<br/><br/>Il est donc conseillé de créer ces indicateurs en formant des groupes de travail regroupant des responsables métiers ainsi que des membres de votre DSI.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/609552290d93fd42890f0e53_outil12.svg", "imageAlt": "Engagez les métiers dans la construction des indicateurs" }, { "type": "intro", "title": "En conclusion, voici les deux règles principales à respecter pour élaborer des indicateurs de tableaux de bord qui boosteront vos performances :", "body": "<p>L'importance de l'innovation ne cesse de s'accroitre pour les entreprises : les projets digitaux se multiplient et leur réussite deviennent une condition sine qua none à la compétitivité de l'organisation. En conséquence, les entreprises ont de plus en plus d'attentes envers les DSI, qui se retrouvent souvent au coeur des nouvelles stratégies mises en place.</p><p>Notre tableau de bord projet a été créé afin de permettre à la DSI d'être en capacité de répondre aux besoins de son entreprise et de collaborer étroitement avec les métiers.</p><ul><li>Pensez-les au regard des caractéristiques propres de votre entreprise</li><li>Co-construisez les avec des responsables métiers impliqués</li></ul><p>En suivant ces principes, vous maximisez vos chances de créer un tableau de bord simplifiant véritablement le pilotage de votre DSI.</p>" }, { "type": "cta", "title": "Découvrez comment AirSaas peut vous aider", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }] }, { "slug": "tableau-de-bord-portefeuille-de-projet", "type": "solution", "meta": { "title": "Le tableau de bord de portefeuille de projet collaboratif et moderne | AirSaas", "description": "AirSaas a développé un tableau de bord de portefeuille de projet personnalisable, à l'expérience utilisateur fluide, qui fluidifie la gouvernance des programmes de transformation au quotidien." }, "sections": [{ "type": "hero", "tag": "SOLUTION", "title": "Le tableau de bord de portefeuille de projet ", "titleSuffix": "collaboratif et moderne", "body": "<p>En matière de portfolio project management, chaque entreprise présente des besoins différents. C'est pour satisfaire ces besoins qu'AirSaas a développé un tableau de bord de portefeuille de projet personnalisable, à l'expérience utilisateur fluide, qui fluidifie la gouvernance des programmes de transformation au quotidien.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "Le tableau de bord de portefeuille de projet préféré des <strong>PMO et DSI</strong>", "body": "<p>AirSaas a été conçu grâce aux retours de professionnels de la transformation d'entreprise sur leurs outils traditionnels de <a href=\"https://www.airsaas.io/fr/gestion-de-projet/comment-elaborer-un-reporting-efficace\">gestion de portefeuilles de projets</a>. Manque de simplicité d'utilisation des tableaux de bord, manque de visibilité à la fois macro et spécifique à chaque projet, manque de personnalisation des dashboards en fonction des spécificités de leur organisation : leurs précieux retours étaient nombreux.<br><br>Face à ces retours, la plateforme AirSaas a été développée comme un outil gain-de-temps pour les DSI et PMO qui veulent obtenir une visibilité en temps réel sur leur <a href=\"https://www.airsaas.io/fr/gestion-de-projet/management-de-portefeuille-de-projet\">portfolio de projets</a>, et qui cherchent à accélérer la prise de décision en Copil.</p>" }, { "type": "intro", "title": "<strong>Visualisez</strong> votre portefeuille de projets en mode macro", "body": "<p>Grâce à AirSaas, sortez des <a href=\"https://www.airsaas.io/fr/solution/outils-de-pilotage-projet\">outils de gestion de projet traditionnels</a> qui rentrent trop dans le suivi de tâches micro, et gagnez du temps avec une vue exhaustive de l'ensemble de vos données-clés. L'objectif : vous focaliser sur la gouvernance de votre portefeuille, dans une vue multi-projets hyper claire.</p>" }, { "type": "feature-split", "title": "Une vue macro au service de votre <strong>planification stratégique</strong>", "body": "<p>Si AirSaas est le tableau de bord de portefeuille projet préféré de bon nombre de PMO et DSI, c'est parce qu'il permet de bénéficier d'une vue macro de l'ensemble des projets qu'ils gèrent.<br><br>Sur la plateforme, toutes les informations-clés dont vous avez besoin sont rassemblées et consolidées, toujours à jour. Cette vue exhaustive vous fait prendre de la hauteur, et vous aide à <a href=\"https://www.airsaas.io/fr/gestion-de-projet/kpi-gestion-de-projet\">prendre les meilleures décisions</a>, en fonction des priorités stratégiques de votre organisation.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "planification stratégique", "reversed": true }, { "type": "feature-split", "title": "Pas besoin de reporter vos données à la main grâce aux <strong>intégrations natives</strong>", "body": "<p>La marketplace d'intégrations natives d'AirSaas facilite la mise à jour de vos tableaux de bord de gestion de projets, en évitant le report de données à la main.<br><br>Vous y trouverez des intégrations à vos outils de gestion de tâches préférés (Jira, Asana, ClickUp, Monday), à vos outils de communication interne (Microsoft Teams), ou à votre logiciel de service client (Zendesk).</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65c4fa645ae196734feb2eca_integrations-screen-home.webp", "imageAlt": "intégrations natives", "reversed": false }, { "type": "intro", "title": "<strong>Personnalisez les vues de votre tableau</strong> de bord de portefeuille projet", "body": "<p>Au-delà d'une vue macro, vous devez pouvoir vous focaliser sur les projets qui en ont besoin - ceux qui sont à risques, dont les délais ont été dépassés, ou qui viennent tout juste d'être lancés. Les vues personnalisables d'AirSaas, filtrées selon la météo, l'état d'avancement ou encore les risques des projets, sont idéales pour la préparation de votre Copil ou de vos <a href=\"https://www.airsaas.io/fr/gestion-de-projet/reporting-pmo\">bilans de projets</a>.</p>" }, { "type": "feature-split", "title": "La vue <strong>liste</strong>", "body": "<p>Elle vous permet de suivre l'avancée de chacun de vos projets et des indicateurs qui y sont liés. Passez en revue vos projets pour savoir à tout moment où vous en êtes, et comment faire évoluer vos projets vers la prochaine étape.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d707b3e6ce3f9970b2d505_Portfolio%20project%20list%20view.webp", "imageAlt": "List", "reversed": false }, { "type": "feature-split", "title": "La vue <strong>Kanban</strong>", "body": "<p>Besoin de repérer des tendances générales dans votre portefeuille de projets ? Passez en vue Kanban, et observez les états d'avancement de vos projets pour optimiser votre stratégie de pilotage.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d70552a7607dc102dcc930_Portfolio%20header%20menu.webp", "imageAlt": "Kanban", "reversed": true }, { "type": "feature-split", "title": "La vue <strong>timeline</strong>", "body": "<p>Sous forme de diagramme de Gantt, elle vous permet d'organiser vos projets sur le temps long. Repérez à l'avance les surcharges en termes de gestion des ressources et les dépendances inter-projets, et anticipez les retards.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Timeline", "reversed": false }, { "type": "cta-highlight", "title": "Faites passer votre portfolio management à <strong>la vitesse supérieure</strong>", "body": "<p>Choisissez un outil PPM collaboratif et moderne, qui simplifie vos prises de décisions et booste votre reporting.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "intro", "title": "<strong>Automatisez</strong> votre reporting", "body": "<p>Finie la perte de temps passée à récolter et consolider les données à droite et à gauche, auprès des métiers, des chefs de projets et de toutes les parties prenantes opérationnelles. En plus d'un tableau de bord de portefeuille de projet, AirSaas vous propose une fonctionnalité de flash report automatisé, qui vous fait gagner en moyenne une journée de travail par semaine.</p>" }, { "type": "feature-split", "title": "Un flash report pour fluidifier la prise de <strong>décision</strong>", "body": "<p>Le reporting flash automatisé d'AirSaas permet à vos différentes parties prenantes (décisionnaires, sponsors, chefs d'équipe et de projet…) de comprendre quelles décisions doivent être prises sur le moment.<br><br>Sa structure rappelle les grandes lignes des projets (planning, timeline, indicateurs-clés…) pour ensuite rentrer dans le détails des projets urgents. Jalons, statuts, risques et météos des projets, métriques d'avancée, gains attendus, ressources humaines et budgets impliqués : tout s'y trouve pour faciliter votre prise de décision.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": false }, { "type": "feature-split", "title": "Une <strong>structure</strong> bien huilée et personnalisable", "body": "<p>Le flash report d'AirSaas se crée en un clic au format .ppt ou .pdf, dans une structure aisément lisible. Vous pouvez personnaliser le design de votre présentation aux couleurs de votre entreprise, et décider d'y ajouter des métriques-clés supplémentaires, un récapitulatif des décisions à prendre, ou encore des précisions sur les plannings de vos projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Reporting projet", "reversed": true }, { "type": "intro", "title": "<strong>Collaborez</strong> pour mieux transformer", "body": "<p>Grâce à AirSaas, vous n'êtes plus seul dans votre portfolio management. Vos chefs de projets et métiers vous aident très aisément, en vous aidant à cadrer vos projets en amont, et en vous indiquant les changements à l'œuvre sur leurs projets au quotidien. Tout le monde est informé, et votre transformation d'entreprise va plus vite, plus loin.</p>" }, { "type": "feature-split", "title": "Co-créez vos fiches de <strong>cadrage</strong>", "body": "<p>Sur AirSaas, créez les fiches de cadrage de vos projets en mode collaboratif, sur une structure fixe qui standardise votre culture projet. Les chefs de projet remplissent ces fiches grâce à une méthodologie forte - pour qu'aucun projet ne commence jamais sur le mauvais pied.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "cadrage", "reversed": true }, { "type": "feature-split", "title": "Communiquez aisément avec <strong>toutes vos parties prenantes</strong>", "body": "<p>Depuis AirSaas, paramétrez les notifications que vous envoyez à vos équipes opérationnelles lorsqu'un projet est à risque. Vous pouvez également envoyer automatiquement des bilans de la période, paramétrables à échéances fixes sur la plateforme.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d47452aa2dd357ad578e4d_Modal%20-%20people%20involved.webp", "imageAlt": "Communiquez", "reversed": false }, { "type": "feature-split", "title": "Partagez vos <strong>bilans de projet</strong> pour motiver tout le monde", "body": "<p>Quand un projet se termine, il est temps d'en tirer les bonnes pratiques et ce qui peut être amélioré en matière de gestion de projet. Engagez vos différentes parties prenantes grâce aux bilans de projets AirSaas, que vous concevez automatiquement via la plateforme.<br><br>Analysez les coûts, les délais, l'engagement de vos équipes et leurs retours DAKI, et félicitez chacun pour les efforts accomplis - et ceux à venir !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d4872337663b8b88c2c66a_Presentation-review-slide.webp", "imageAlt": "bilans de projet", "reversed": true }, { "type": "intro", "title": "<strong>Les clés</strong> de succès pour concevoir votre tableau de bord de gouvernance projet", "body": "<p>Bon nombre de PMO ou de DSI choisissent de partir d'un modèle de tableau de bord de portefeuille de projet pour concevoir le leur. Cependant, la meilleure pratique consiste à créer le vôtre propre, grâce à l'aide d'un outil PPM performant. Suivez ces règles d'or pour faire en sorte que vos tableaux de bord suivent et boostent vraiment votre performance.</p>" }, { "type": "feature-split", "title": "Choisissez bien vos <strong>indicateurs de performance</strong>", "body": "<p>Les indicateurs que vous intégrez à votre tableau de bord de portefeuille de projet doivent à la fois analyser le passé, le présent, et les événements à venir dans votre portfolio. Il sont à la fois des outils de reporting, et des clés pour piloter votre gouvernance.<br><br>Construisez vos indicateurs à la fois autour de vos processus (KPI dynamiques) et de vos résultats (KPI statiques). Veillez également à ce qu'ils soient comparables entre eux lorsque cela est possible.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010195cd30eca1a1bd8bb_outil10.svg", "imageAlt": "indicateurs de performance", "reversed": false }, { "type": "feature-split", "title": "Construisez <strong>les KPI</strong> de votre tableau de bord en fonction de vos besoins", "body": "<p>S'il est tentant de partir d'un template de tableau de bord universel, il est crucial d'adapter les indicateurs qui s'y trouvent aux ambitions et besoins de votre entreprise. Il s'agit d'un élément essentiel pour assurer le pilotage de votre DSI.<br><br>Prenez en compte le contexte de votre entreprise (collaborateurs, projets menés, résultats escomptés), ainsi que ce que vous savez de chacune de ses activités.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010d54008b63e9415adb6_outil11.svg", "imageAlt": "les KPI", "reversed": true }, { "type": "feature-split", "title": "Co-construisez vos tableaux de bord avec <strong>les métiers</strong>", "body": "<p>Pour obtenir un tableau de bord de portfolio management personnalisé, impliquez les directions métiers dans son élaboration. Après tout, ce sont eux les destinataires et utilisateurs des solutions que vos projets développent !<br><br>Créez vos indicateurs dans des groupes de travail qui rassemblent responsables métiers et membres de votre DSI. C'est là le gage d'un tableau de bord bien ficelé, et de livrables adaptés aux attentes de leurs utilisateurs finaux.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65a010238635278f1f6cecf1_outil12.svg", "imageAlt": "les métiers", "reversed": false }, { "type": "feature-split", "title": "Rendez vos <strong>indicateurs limpides</strong> pour tous", "body": "<p>Un bon tableau de bord de portefeuille de projet doit être aisément lisible par l'ensemble de vos parties prenantes.<br><br>Veillez donc à nommer chacun de vos indicateurs, et à les définir pour vous assurer que chacun utilise la même définition. Si possible, liez à chaque indicateur un objectif chiffré. Et n'oubliez pas de définir la fréquence à laquelle votre indicateur doit être mis à jour : semestrielle, mensuelle, ou hebdomadaire.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d73abfdd38dac29b4e219c_Project%20page%20zoom%20weather.webp", "imageAlt": "Project page zoom weather", "reversed": true }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou .Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)" }] }, { "type": "cta", "title": "Choisissez de <strong>gagner du temps</strong> et du contrôle", "body": "<p>Adoptez dès maintenant un tableau de bord de portefeuille de projet efficace, dont l'expérience utilisateur se met au service de votre portfolio management.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }] }] as const;

export const PAGES_BY_SLUG: Record<string, LandingPage> =
  Object.fromEntries(PAGES.map((p) => [p.slug, p]));
